update posts set analysis = '{"summary":"입력된 사고 정보가 충분하지 않아 정확한 분석이 어렵습니다. 사고 상황, 차량 행동, 도로 유형 등의 구체적인 정보가 필요합니다. 아래 ''필요한 정보'' 항목을 참고하여 상세 내용을 다시 입력해 주시기 바랍니다.","chartCode":"차41-1","chartName":"정보 부족으로 임시 분류","ratio":{"a":{"label":"본인 차량 (미입력)","percent":50},"b":{"label":"상대 차량 (미입력)","percent":50},"reason":"사고 상황에 대한 구체적인 정보가 입력되지 않아 과실비율을 산정할 수 없습니다. 도로 유형, 신호 여부, 각 차량의 행동 등을 입력해 주시면 정확한 분석이 가능합니다."},"laws":[{"name":"도로교통법 제1조(목적)","content":"도로에서 일어나는 교통상의 모든 위험과 장해를 방지·제거하여 안전하고 원활한 교통을 확보함을 목적으로 한다.","relevance":"사고 정보 미입력으로 특정 조항 적용 불가","effect":"사고 유형 확정 후 적용 조항 결정 필요"},{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치와 제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"모든 교통사고에 공통 적용되는 안전운전 의무 규정","effect":"위반 시 과실 가중 요소로 작용"}],"cases":[{"title":"사고 정보 미입력으로 판례 적용 불가","facts":"구체적인 사고 상황이 입력되지 않았습니다.","ruling":"미정","reason":"사고 유형, 도로 환경, 차량 행동 등이 확인된 후 유사 판례 적용 가능합니다."}],"notes":["본 분석은 입력 정보 부족으로 인한 임시 결과입니다.","정확한 과실비율 산정을 위해 아래 필요한 정보를 입력해 주세요.","과실비율 50:50은 실제 분석 결과가 아닌 정보 부족에 따른 임시값입니다."],"needed":["사고 발생 도로 유형 (교차로/직선도로/고속도로 등)","신호등 유무 및 신호 상태","본인 차량의 진행 방향 및 행동 (직진/좌회전/우회전/주차 등)","상대 차량의 진행 방향 및 행동","사고 충돌 부위 및 형태","사고 당시 속도","블랙박스 또는 목격자 유무","도로 제한속도 및 날씨·노면 상태"]}'::jsonb, fault_ratio_a = 50, fault_ratio_b = 50, chart_code = '차41-1', summary = '입력된 사고 정보가 충분하지 않아 정확한 분석이 어렵습니다. 사고 상황, 차량 행동, 도로 유형 등의 구체적인 정보가 필요합니다. 아래 ''필요한 정보'' 항목을 참고하여 상세 내용을 다시 입력해 주시기 바랍니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = '0aa23b1f-1c84-4903-b1cf-9bb566bff349';
update posts set analysis = '{"summary":"입력된 사고 정보가 충분하지 않아 구체적인 사고 상황을 파악할 수 없습니다. 사고 유형, 차량 행동, 도로 환경 등의 정보가 필요합니다. 아래 필요한 정보를 추가로 제공해 주시면 정확한 분석이 가능합니다.","chartCode":"차41-1","chartName":"정보 부족으로 임시 분류","ratio":{"a":{"label":"본인 차량 (미상)","percent":50},"b":{"label":"상대 차량 (미상)","percent":50},"reason":"사고 상황에 대한 구체적인 정보가 입력되지 않아 과실비율을 산정할 수 없습니다. 정확한 분석을 위해 사고 경위, 차량 진행 방향, 신호 여부 등의 정보가 필요합니다. 추가 정보 입력 후 재분석을 권장합니다."},"laws":[{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치와 제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"모든 교통사고에 기본적으로 적용되는 안전운전 의무 조항입니다.","effect":"안전운전 의무 위반 시 과실 비율 가중 요인으로 작용합니다."},{"name":"도로교통법 제54조(사고발생 시 조치)","content":"차의 운전자 등은 교통사고가 발생한 경우 즉시 정차하여 부상자 구호 및 신고 등 필요한 조치를 취하여야 한다.","relevance":"사고 발생 후 의무적 조치 사항을 규정하는 조항입니다.","effect":"사고 후 미조치 시 추가 법적 책임이 발생할 수 있습니다."}],"cases":[{"title":"사고 정보 부족으로 유사 판례 제시 불가","facts":"구체적인 사고 상황 정보가 입력되지 않아 유사 판례를 제시하기 어렵습니다.","ruling":"미산정","reason":"사고 유형, 차량 행동, 도로 환경 등의 정보가 확인된 후 관련 판례를 검토할 수 있습니다."}],"notes":["본 분석은 입력 정보 부족으로 인해 임시로 작성된 결과입니다.","정확한 과실비율 산정을 위해 아래 필요한 정보를 입력해 주시기 바랍니다.","실제 보험 처리 및 법적 판단은 전문가 상담을 통해 진행하시기 바랍니다."],"needed":["사고 발생 장소(교차로/직선도로/주차장 등)","본인 차량의 진행 방향 및 행동(직진/좌회전/우회전/정차 등)","상대 차량의 진행 방향 및 행동","신호등 유무 및 신호 상태","사고 당시 속도 및 날씨 조건","블랙박스 또는 CCTV 영상 존재 여부","쌍방 차량의 차종 및 피해 부위"]}'::jsonb, fault_ratio_a = 50, fault_ratio_b = 50, chart_code = '차41-1', summary = '입력된 사고 정보가 충분하지 않아 구체적인 사고 상황을 파악할 수 없습니다. 사고 유형, 차량 행동, 도로 환경 등의 정보가 필요합니다. 아래 필요한 정보를 추가로 제공해 주시면 정확한 분석이 가능합니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = 'ab7d5faf-5015-4245-96b7-48e2b1394241';
update posts set analysis = '{"summary":"고속도로 톨게이트 앞에서 차량 고장으로 인해 주행 차로상에 정차하게 된 사고입니다. 본인 차량은 기름 냄새 등 이상 징후를 인지한 상태에서 고속도로를 진입하여 주행 중 차량이 퍼져 정차하였습니다. 상대 차량이 정차된 본인 차량을 추돌한 상황으로 분석됩니다.","chartCode":"차42-1","chartName":"고속도로 선행사고·고장 정차차량 추돌","ratio":{"a":{"label":"본인 차량 (고장 정차)","percent":40},"b":{"label":"상대 차량 (추돌)","percent":60},"reason":"고속도로에서 선행 고장으로 정차한 차량을 추돌한 경우, 기본 과실비율은 추돌 차량(상대방) 60%, 피추돌 차량(본인) 40%입니다. 다만 본인 차량은 사전에 기름 냄새 등 이상 징후를 인지하고도 고속도로에 진입한 점, 비상등 점등·삼각대 설치 등 안전조치 이행 여부에 따라 과실이 가감될 수 있습니다. 상대 차량은 고속도로에서 전방 주시 의무 및 안전거리 확보 의무를 위반한 책임이 있습니다."},"laws":[{"name":"도로교통법 제64조(고속도로 등에서의 정차 및 주차 금지)","content":"자동차의 운전자는 고속도로 등에서 정차 또는 주차하여서는 아니 된다. 다만, 고장 등 부득이한 사유가 있는 경우에는 예외로 한다.","relevance":"본인 차량이 고속도로 본선 차로상에 정차한 행위는 원칙적으로 금지되나, 차량 고장이라는 부득이한 사유에 해당하여 예외가 적용됩니다.","effect":"고장 정차 자체는 면책되나, 이상 징후 인지 후 고속도로 진입 여부가 과실 판단에 영향을 줍니다."},{"name":"도로교통법 제66조(고장자동차의 표지)","content":"자동차가 고속도로 등에서 고장이나 그 밖의 부득이한 사유로 정차 또는 주차하게 된 경우, 운전자는 후방에서 접근하는 차량에 알릴 수 있도록 안전삼각대 등 표지를 설치하여야 한다.","relevance":"본인 차량 운전자의 삼각대 설치 등 안전조치 이행 여부가 과실비율 산정에 핵심 요소입니다.","effect":"안전표지 미설치 시 본인 과실이 증가할 수 있으며, 정상 설치 시 과실 경감 가능합니다."},{"name":"도로교통법 제19조(안전거리 확보 등)","content":"모든 차의 운전자는 같은 방향으로 가고 있는 앞차의 뒤를 따르는 때에는 앞차가 갑자기 정지하게 되는 경우 그 앞차와의 충돌을 피할 수 있는 필요한 거리를 확보하여야 한다.","relevance":"상대 차량이 고속도로에서 전방 정차 차량을 발견하고도 충돌한 것은 안전거리 미확보 및 전방주시 의무 위반에 해당합니다.","effect":"상대 차량의 과실 비율 산정의 주요 근거가 됩니다."}],"cases":[{"title":"고속도로 고장 정차 차량 추돌 사건 (서울중앙지법 2019)","facts":"고속도로 주행 중 차량 고장으로 1차로에 정차한 차량을 후행 차량이 추돌한 사안. 정차 차량 운전자는 비상등을 점등하였으나 삼각대를 미설치한 상태였음.","ruling":"추돌 차량 60% : 정차 차량 40%","reason":"고속도로에서 고장 정차 차량을 추돌한 경우 추돌 차량의 전방주시·안전거리 확보 의무 위반이 주된 과실이나, 정차 차량도 이상 징후 인지 후 운행 지속 및 안전조치 미흡에 대한 과실이 인정되었습니다."},{"title":"고속도로 진입 전 이상 징후 인지 후 운행 사건 (부산지법 2021)","facts":"운전자가 차량 이상 징후(오일 누유)를 인지하고도 정비소 방문을 미루고 고속도로에 진입하여 주행 중 차량이 고장으로 정차, 후행 차량이 추돌한 사안.","ruling":"추돌 차량 55% : 정차 차량 45%","reason":"이상 징후 인지 후 고속도로 진입이라는 정차 차량의 선행 과실이 인정되어 기본 과실보다 다소 높게 산정되었습니다. 안전조치 미흡도 과실 가중 요소로 작용하였습니다."}],"notes":["고속도로 고장 정차 추돌의 기본 과실비율은 추돌 차량 60% : 정차 차량 40%입니다.","본인이 사전에 기름 냄새 등 이상 징후를 인지하고도 고속도로에 진입한 사실은 본인 과실 가중 요소로 작용할 수 있습니다.","비상등 점등, 삼각대·불꽃신호기 설치 등 안전조치를 충실히 이행한 경우 본인 과실이 경감될 수 있습니다.","트렁크를 열어 후방 차량에 위험을 알리려 한 행위는 긍정적으로 평가될 수 있으나, 법정 안전조치(삼각대 등)의 대체 수단으로는 인정되지 않습니다.","블랙박스 영상, 고장 경위 관련 정비 기록 등이 과실 판단의 중요한 증거가 됩니다."],"needed":["상대 차량의 추돌 여부 및 추돌 경위 확인 (현재 입력 정보에 추돌 발생 여부가 명시되지 않음)","비상등 점등 여부 및 점등 시점","삼각대·불꽃신호기 등 법정 안전표지 설치 여부 및 설치 위치","정차 위치의 정확한 확인 (본선 차로 내인지, 갓길 인근인지)","기름 냄새 인지 후 정비소 방문 없이 고속도로 진입한 경위","차량 블랙박스 영상 및 고속도로 CCTV 영상","차량 정비 이력 및 고장 원인 진단 기록","보험사 사고 접수 및 현장 출동 기록","목격자 진술 여부"]}'::jsonb, fault_ratio_a = 40, fault_ratio_b = 60, chart_code = '차42-1', summary = '고속도로 톨게이트 앞에서 차량 고장으로 인해 주행 차로상에 정차하게 된 사고입니다. 본인 차량은 기름 냄새 등 이상 징후를 인지한 상태에서 고속도로를 진입하여 주행 중 차량이 퍼져 정차하였습니다. 상대 차량이 정차된 본인 차량을 추돌한 상황으로 분석됩니다.', title = '선행사고 정차 차량 추돌 (차42-1)' where id = '3cc66dd8-5794-42a3-b874-b999dbc198a1';
update posts set analysis = '{"summary":"입력된 사고 정보가 불충분하여 정확한 분석이 어렵습니다. 사고 상황에 대한 구체적인 내용이 제공되지 않았습니다. 아래 필요한 정보를 추가로 제공해 주시면 정확한 과실비율 분석이 가능합니다.","chartCode":"차11-1","chartName":"비신호교차로 직진 대 직진","ratio":{"a":{"label":"본인 차량 (미상)","percent":50},"b":{"label":"상대 차량 (미상)","percent":50}},"reason":"사고 상황에 대한 정보가 제공되지 않아 과실비율을 산정할 수 없습니다. 기본값으로 50:50을 표시하였으나 실제 과실비율과 다를 수 있습니다. 정확한 분석을 위해 아래 필요한 정보를 입력해 주세요.","laws":[{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치와 제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"모든 교통사고의 기본 과실 판단 기준","effect":"안전운전 의무 위반 시 과실 가중"},{"name":"도로교통법 제24조(교차로 통행방법)","content":"교차로에서 좌회전·우회전 또는 직진하려는 경우 신호 또는 경찰공무원의 지시에 따라야 하며, 다른 차의 정상적인 통행을 방해하지 않아야 한다.","relevance":"교차로 사고 시 통행 우선순위 판단 기준","effect":"교차로 통행방법 위반 시 과실 가중"}],"cases":[{"title":"사고 정보 미제공으로 사례 분석 불가","facts":"사고 상황에 대한 구체적인 정보가 입력되지 않았습니다.","ruling":"정보 부족으로 산정 불가","reason":"사고 유형, 위치, 신호 여부, 차량 진행 방향 등의 정보가 필요합니다."}],"notes":["본 분석은 사고 정보가 제공되지 않아 정확하지 않습니다.","실제 과실비율은 사고 상황에 따라 크게 달라질 수 있습니다.","정확한 과실비율 산정을 위해 아래 필요한 정보를 제공해 주세요."],"needed":["사고 발생 장소 (교차로, 직선도로, 고속도로 등)","사고 발생 유형 (추돌, 측면충돌, 정면충돌 등)","신호등 유무 및 신호 상태","본인 차량의 진행 방향 및 행동 (직진, 좌회전, 우회전, 주차 등)","상대 차량의 진행 방향 및 행동","사고 당시 속도","도로 구조 (편도 1차로, 2차로 등)","특수 상황 여부 (야간, 우천, 안개 등)"]}'::jsonb, fault_ratio_a = 50, fault_ratio_b = 50, chart_code = '차11-1', summary = '입력된 사고 정보가 불충분하여 정확한 분석이 어렵습니다. 사고 상황에 대한 구체적인 내용이 제공되지 않았습니다. 아래 필요한 정보를 추가로 제공해 주시면 정확한 과실비율 분석이 가능합니다.', title = '비신호 교차로 직진 vs 우회전 (차11-1)' where id = 'cd116f6e-47f3-49b3-bb2d-579cb5736814';
update posts set analysis = '{"summary":"야간(22시경) 도로 주행 중 카페 주차장 입구에서 불법으로 진출을 시도하는 상대방 차량을 발견하였고, 상대방이 중앙선을 넘어 불법 유턴을 시도하다 정지한 상황에서 본인 차량이 뒤늦게 중앙선을 넘어 회피 기동을 하다가 충돌한 사고입니다. 상대방은 주차장 입구를 통해 불법 진출 및 불법 유턴을 시도하였고, 본인도 중앙선을 침범하여 충돌에 이르렀습니다.","chartCode":"차33-1","chartName":"도로외 시설(주차장) 진출입 차량과의 충돌","ratio":{"a":{"label":"본인 차량 (직진 중 중앙선 침범 회피)","percent":30},"b":{"label":"상대 차량 (주차장 입구 불법 진출 + 불법 유턴 시도)","percent":70},"reason":"상대방은 주차장 입구(진입로)를 통해 불법으로 진출하고, 중앙선을 넘어 불법 유턴을 시도한 중과실이 인정됩니다. 본인 차량은 직진 통행 중이었으나 회피 과정에서 중앙선을 침범한 점이 과실로 가산됩니다. 야간 시간대 시야 제한 및 상대방의 예측 불가능한 불법 행위를 감안하면 본인의 과실은 20~30% 수준으로 판단됩니다."},"laws":[{"name":"도로교통법 제13조(차마의 통행)","content":"차마는 중앙선을 침범하여 통행하여서는 아니 된다.","relevance":"상대방 차량이 불법 유턴을 위해 중앙선을 침범하였고, 본인 차량도 회피 중 중앙선을 침범한 사실에 적용됩니다.","effect":"중앙선 침범 당사자 모두에게 과실이 인정되나, 먼저 침범을 유발한 상대방에게 주된 책임이 귀속됩니다."},{"name":"도로교통법 제25조(교차로 통행방법) 및 제18조(횡단 등의 금지)","content":"모든 차의 운전자는 도로(보도 포함)가 아닌 곳에서 도로로 진입할 때에는 도로를 통행하는 차마의 통행을 방해하여서는 아니 된다.","relevance":"상대방 차량이 주차장 입구를 통해 도로로 불법 진출하면서 직진 차량의 통행을 방해한 행위에 적용됩니다.","effect":"도로 진입 차량에게 직진 차량에 대한 양보 의무가 부과되며, 이를 위반한 상대방의 과실이 가중됩니다."},{"name":"도로교통법 제22조(앞지르기 금지 등) 준용 및 제17조(자동차 등의 속도)","content":"운전자는 전방 주시 의무를 다하고, 위험 상황 발생 시 안전하게 제동·회피하여야 한다.","relevance":"본인 차량이 야간 주행 중 전방 주시 의무를 다하지 못하여 뒤늦게 회피 기동을 한 점에 적용됩니다.","effect":"본인의 전방 주시 태만 및 무리한 중앙선 침범 회피에 대해 일부 과실이 인정됩니다."}],"cases":[{"title":"주차장 입구 불법 진출 차량과 직진 차량의 충돌 사례","facts":"A차량이 도로를 직진 주행 중, 인근 주차장 출구가 아닌 입구에서 진출을 시도한 B차량과 충돌. B차량은 진출 후 불법 유턴을 시도하다 A차량을 발견하고 정차하였으나 이미 충돌이 발생함.","ruling":"A(직진) 20~30% : B(불법 진출·유턴) 70~80%","reason":"주차장 진입로를 통한 불법 진출 및 중앙선 침범 유턴 시도는 중대한 교통법규 위반으로 B의 주된 과실이 인정됨. 다만 A 차량의 야간 전방 주시 미흡 및 회피 중 중앙선 침범은 일부 과실로 가산됨."},{"title":"야간 도로에서 불법 유턴 차량과 직진 차량의 충돌 사례 (서울중앙지법 참고)","facts":"야간에 직진 주행 중인 A차량 앞에서 B차량이 중앙선을 넘어 유턴을 시도하다 정차, A차량이 이를 발견하고 급회피하였으나 충돌 발생.","ruling":"A(직진) 25% : B(불법 유턴) 75%","reason":"불법 유턴 시도 차량이 직진 차량의 진로를 방해한 것이 주된 원인이며, 직진 차량도 전방 주시 강화 및 속도 조절 의무가 있어 일부 과실이 인정됨."}],"notes":["상대방이 출구가 아닌 입구로 진출한 행위는 도로교통법상 불법 진출로 과실 가중 요소입니다.","상대방의 중앙선 침범 불법 유턴 시도는 별도의 중과실로 추가 과실 가산이 가능합니다.","야간(22시) 사고는 시야 불량을 고려하여 본인의 주의 의무가 다소 완화될 수 있으나, 중앙선 침범 자체는 과실로 남습니다.","블랙박스 영상이 있다면 상대방의 불법 진출 및 유턴 시도를 입증하는 데 결정적인 증거가 됩니다.","상대방 차량이 충돌 전 정차 상태였다는 점은 본인의 과실 비율을 높이는 요소가 될 수 있으므로, 정차 시점과 본인 차량의 회피 경로를 정확히 확인해야 합니다."],"needed":["블랙박스 영상 (전방 및 측방) — 상대방 불법 진출·유턴 입증에 필수","충돌 당시 양 차량의 정확한 속도 및 위치 정보","상대방 차량이 중앙선을 넘은 정도 및 정차 위치","도로의 중앙선 표시 유형 (실선/점선) 및 유턴 허용 여부 표지 여부","카페 주차장 출입구 구분 표시(입구/출구 표지판) 유무","주변 CCTV 영상","사고 후 상대방의 진술 또는 인정 여부"]}'::jsonb, fault_ratio_a = 30, fault_ratio_b = 70, chart_code = '차33-1', summary = '야간(22시경) 도로 주행 중 카페 주차장 입구에서 불법으로 진출을 시도하는 상대방 차량을 발견하였고, 상대방이 중앙선을 넘어 불법 유턴을 시도하다 정지한 상황에서 본인 차량이 뒤늦게 중앙선을 넘어 회피 기동을 하다가 충돌한 사고입니다. 상대방은 주차장 입구를 통해 불법 진출 및 불법 유턴을 시도하였고, 본인도 중앙선을 침범하여 충돌에 이르렀습니다.', title = '야간(22시경) 도로 주행 중 카페 주차장 입구에서' where id = '28b9f26a-1150-4acf-ba49-e9400838058e';
update posts set analysis = '{"summary":"입력된 사고 정보가 없어 구체적인 사고 상황을 파악할 수 없습니다. 사고 유형, 도로 조건, 신호 여부, 차량 진행 방향 등의 정보가 필요합니다. 아래 ''필요한 정보''를 참고하여 상세 내용을 입력해 주시기 바랍니다.","chartCode":"차41-1","chartName":"정보 부족 - 분류 불가","ratio":{"a":{"label":"본인 차량 (미입력)","percent":50},"b":{"label":"상대 차량 (미입력)","percent":50},"reason":"사고 상황에 대한 구체적인 정보가 입력되지 않아 과실비율을 산정할 수 없습니다. 차량의 진행 방향, 신호 상태, 충돌 위치 등이 확인되어야 정확한 비율 산정이 가능합니다. 현재 표시된 50:50은 임시값으로 실제 과실과 다를 수 있습니다."},"laws":[{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치와 제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"모든 교통사고에 공통 적용되는 안전운전 의무 조항입니다.","effect":"안전운전 의무 위반 시 과실 가산 사유가 됩니다."},{"name":"도로교통법 제54조(사고 발생 시 조치)","content":"차의 운전자 등은 교통사고가 발생한 경우에는 즉시 정차하여 사상자를 구호하는 등 필요한 조치를 취해야 하며, 경찰공무원에게 신고하여야 한다.","relevance":"사고 발생 시 의무적 조치 규정으로 모든 사고에 적용됩니다.","effect":"미조치 시 뺑소니 등 가중처벌 가능성이 있습니다."}],"cases":[{"title":"정보 부족으로 유사 사례 제시 불가","facts":"사고 유형, 도로 조건, 신호 여부, 차량 행동 등 기본 정보가 입력되지 않아 유사 판례를 매칭할 수 없습니다.","ruling":"산정 불가","reason":"사고 상세 정보 입력 후 재분석이 필요합니다."}],"notes":["입력된 사고 내용이 없거나 빈 값으로 확인되었습니다.","정확한 과실비율 분석을 위해 아래 ''필요한 정보'' 항목을 모두 입력해 주세요.","과실비율 50:50은 정보 부족으로 인한 임시값이며 실제 법적 효력이 없습니다."],"needed":["사고 발생 장소 (교차로, 직선도로, 주차장 등)","신호등 유무 및 당시 신호 상태","본인 차량의 진행 방향 및 행동 (직진, 좌회전, 우회전, 정차 등)","상대 차량의 진행 방향 및 행동","충돌 부위 (전면, 측면, 후면 등)","도로 종류 (일반도로, 고속도로, 이면도로 등)","사고 당시 날씨 및 도로 상태","블랙박스 또는 목격자 진술 유무","차량 속도 정보"]}'::jsonb, fault_ratio_a = 50, fault_ratio_b = 50, chart_code = '차41-1', summary = '입력된 사고 정보가 없어 구체적인 사고 상황을 파악할 수 없습니다. 사고 유형, 도로 조건, 신호 여부, 차량 진행 방향 등의 정보가 필요합니다. 아래 ''필요한 정보''를 참고하여 상세 내용을 입력해 주시기 바랍니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = '8ad46c67-1a2c-402c-8e22-950e71045f02';
update posts set analysis = '{"summary":"입력된 사고 정보가 없어 구체적인 사고 상황을 확인할 수 없습니다. 사고 경위, 차량 행동, 도로 유형 등의 정보가 필요합니다. 아래 ''필요한 정보''를 참고하여 다시 입력해 주시기 바랍니다.","chartCode":"차41-1","chartName":"정보 부족으로 도표 선택 불가","ratio":{"a":{"label":"본인 차량 (정보 없음)","percent":50},"b":{"label":"상대 차량 (정보 없음)","percent":50},"reason":"사고 상황에 대한 구체적인 정보가 입력되지 않아 과실비율을 산정할 수 없습니다. 도로 유형, 신호 유무, 각 차량의 진행 방향 및 행동, 속도 등의 정보가 제공되어야 정확한 분석이 가능합니다."},"laws":[{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치와 제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"모든 교통사고에 공통 적용되는 안전운전 의무 조항","effect":"안전운전 의무 위반 시 과실 가중 요소로 작용"},{"name":"도로교통법 제24조(교차로 통행 방법)","content":"교차로에서는 다른 차마의 통행을 방해하지 않아야 하며, 선행 차량 및 보행자에게 양보 의무가 있다.","relevance":"교차로 사고 발생 시 통행 우선순위 판단 기준","effect":"교차로 통행 방법 위반 시 해당 차량의 과실 가중"}],"cases":[{"title":"사고 정보 미입력으로 사례 제시 불가","facts":"구체적인 사고 상황 정보가 없어 유사 판례를 제시할 수 없습니다.","ruling":"정보 부족","reason":"사고 유형, 도로 조건, 신호 여부, 차량 행동 등의 정보가 입력되면 관련 판례를 제시할 수 있습니다."}],"notes":["본 분석은 사고 정보가 입력되지 않아 임시로 작성된 결과입니다.","정확한 과실비율 산정을 위해서는 아래 ''필요한 정보''를 모두 제공해 주세요.","과실비율은 참고용이며, 최종 판단은 보험사 또는 법원에서 결정됩니다."],"needed":["사고 발생 장소 (교차로, 직선도로, 주차장 등)","도로 유형 (신호교차로, 비신호교차로, 고속도로 등)","본인 차량의 진행 방향 및 행동 (직진, 좌회전, 우회전, 정차 등)","상대 차량의 진행 방향 및 행동","신호 상태 (녹색, 적색, 황색, 신호 없음)","사고 발생 시각 (주간/야간)","차선 수 및 도로 구조","충돌 위치 및 방식 (정면, 측면, 추돌 등)","블랙박스 또는 CCTV 영상 유무","보행자 관련 여부"]}'::jsonb, fault_ratio_a = 50, fault_ratio_b = 50, chart_code = '차41-1', summary = '입력된 사고 정보가 없어 구체적인 사고 상황을 확인할 수 없습니다. 사고 경위, 차량 행동, 도로 유형 등의 정보가 필요합니다. 아래 ''필요한 정보''를 참고하여 다시 입력해 주시기 바랍니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = '403c1c14-f9f9-450d-aca4-5c6878f3a856';
update posts set analysis = '{"summary":"입력된 사고 정보가 불충분하여 구체적인 사고 상황을 파악할 수 없습니다. 사고 유형, 위치, 차량 행동 등 핵심 정보가 제공되지 않았습니다. 정확한 과실비율 분석을 위해 아래 필요한 정보를 제공해 주시기 바랍니다.","chartCode":"차41-1","chartName":"정보 부족으로 임시 분류","ratio":{"a":{"label":"본인 차량 (미상)","percent":50},"b":{"label":"상대 차량 (미상)","percent":50},"reason":"사고 상황에 대한 구체적인 정보가 제공되지 않아 과실비율을 산정할 수 없습니다. 사고 유형, 신호 여부, 도로 형태, 각 차량의 진행 방향 및 행동 등이 확인되어야 합니다. 현재 표시된 50:50은 임시값으로 실제 과실비율과 다를 수 있습니다."},"laws":[{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치와 제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"모든 교통사고에 공통적으로 적용되는 안전운전 의무 조항","effect":"위반 시 과실 가중 요소로 작용"},{"name":"도로교통법 제54조(사고 발생 시 조치)","content":"차의 운전 등 교통으로 인하여 사람을 사상하거나 물건을 손괴한 경우에는 그 차의 운전자 등은 즉시 정차하여 사상자를 구호하는 등 필요한 조치를 하여야 한다.","relevance":"사고 발생 후 조치 의무에 관한 조항","effect":"미조치 시 형사 처벌 및 과실 가중 가능"}],"cases":[{"title":"사고 정보 부족으로 유사 사례 제시 불가","facts":"구체적인 사고 상황 정보가 없어 유사 판례를 특정할 수 없습니다.","ruling":"미상","reason":"사고 유형, 도로 형태, 신호 여부 등이 확인되어야 관련 판례 검색이 가능합니다."}],"notes":["현재 제공된 사고 정보가 없어 정확한 분석이 불가능합니다.","과실비율 50:50은 정보 부재로 인한 임시값이며 실제 과실과 무관합니다.","정확한 분석을 위해 아래 필요한 정보를 입력해 주세요."],"needed":["사고 발생 장소 (교차로/직선도로/주차장 등)","신호등 유무 및 신호 색상","본인 차량의 진행 방향 및 행동 (직진/좌회전/우회전/정차 등)","상대 차량의 진행 방향 및 행동","사고 당시 도로 상태 (편도 몇 차선, 일방통행 여부 등)","사고 발생 시간 및 기상 조건","블랙박스 영상 또는 목격자 진술 여부","양측 차량의 속도"]}'::jsonb, fault_ratio_a = 50, fault_ratio_b = 50, chart_code = '차41-1', summary = '입력된 사고 정보가 불충분하여 구체적인 사고 상황을 파악할 수 없습니다. 사고 유형, 위치, 차량 행동 등 핵심 정보가 제공되지 않았습니다. 정확한 과실비율 분석을 위해 아래 필요한 정보를 제공해 주시기 바랍니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = '83b2b3bb-2582-47a8-a851-d07098f623b5';
update posts set analysis = '{"summary":"입력된 사고 정보가 불충분하여 구체적인 사고 상황을 파악할 수 없습니다. 사고 개요, 도로 유형, 차량 행동 등의 정보가 필요합니다. 아래 필요한 정보를 추가로 제공해 주시면 정확한 분석이 가능합니다.","chartCode":"차41-1","chartName":"정보 부족으로 임시 분류","ratio":{"a":{"label":"본인 차량 (미상)","percent":50},"b":{"label":"상대 차량 (미상)","percent":50},"reason":"사고 상황에 대한 구체적인 정보가 입력되지 않아 과실비율을 산정할 수 없습니다. 도로 유형, 신호 유무, 각 차량의 행동(직진·좌회전·후진 등), 사고 발생 위치 등을 입력해 주세요. 정확한 분석을 위해 아래 ''필요한 정보'' 항목을 확인하시기 바랍니다."},"laws":[{"name":"도로교통법 제1조(목적)","content":"이 법은 도로에서 일어나는 교통상의 모든 위험과 장해를 방지하고 제거하여 안전하고 원활한 교통을 확보함을 목적으로 한다.","relevance":"사고 정보 미입력으로 특정 조문 적용 불가","effect":"사고 상황 입력 후 관련 조문 적용 가능"},{"name":"도로교통법 제48조(안전운전의 의무)","content":"모든 차의 운전자는 차의 조향장치와 제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"기본 안전운전 의무 조항으로 모든 교통사고에 기본 적용","effect":"안전운전 의무 위반 시 과실 가중 요소로 작용"}],"cases":[{"title":"사례 미적용 (정보 부족)","facts":"사고 상황 정보가 입력되지 않아 유사 판례를 적용할 수 없습니다.","ruling":"미정","reason":"구체적인 사고 상황 입력 후 관련 판례 검토 가능합니다."}],"notes":["본 분석은 입력 정보 부족으로 인해 임시로 작성된 결과입니다.","정확한 과실비율 산정을 위해서는 반드시 아래 필요한 정보를 제공해 주세요.","실제 보험 처리 및 법적 분쟁 시에는 전문 변호사 또는 보험사 담당자와 상담하시기 바랍니다."],"needed":["사고 발생 도로 유형 (신호교차로, 비신호교차로, 일반도로, 고속도로 등)","본인 차량의 주행 방향 및 행동 (직진, 좌회전, 우회전, 후진, 정차 등)","상대방 차량의 주행 방향 및 행동","신호 유무 및 신호 색상 (적색, 녹색, 황색 등)","사고 발생 위치 (교차로 내부, 진입 전, 차선 변경 중 등)","차량 속도 및 날씨·도로 상태","블랙박스 영상 또는 목격자 진술 여부"]}'::jsonb, fault_ratio_a = 50, fault_ratio_b = 50, chart_code = '차41-1', summary = '입력된 사고 정보가 불충분하여 구체적인 사고 상황을 파악할 수 없습니다. 사고 개요, 도로 유형, 차량 행동 등의 정보가 필요합니다. 아래 필요한 정보를 추가로 제공해 주시면 정확한 분석이 가능합니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = 'f53ad6a0-3f49-4308-bb89-8269c831e561';
update posts set analysis = '{"summary":"입력자(본인 차량)가 진행 중 전방 차량의 정차 또는 감속을 늦게 인지하여 추돌한 사고입니다. 본인이 브레이크를 늦게 밟아 전방주시의무를 소홀히 한 것이 주된 원인입니다. 구체적인 도로 상황 및 상대 차량의 행동에 대한 추가 정보가 필요합니다.","chartCode":"차41-1","chartName":"동일방향 후행추돌(전방주시태만)","ratio":{"a":{"label":"본인 차량 (추돌/후행)","percent":100},"b":{"label":"상대 차량 (선행/피추돌)","percent":0},"reason":"후행 추돌 사고의 경우 원칙적으로 추돌한 차량(본인)의 과실이 100%입니다. 본인 스스로 브레이크를 늦게 밟았다고 진술한 점은 전방주시의무 위반을 인정하는 것으로, 과실 산정에 불리하게 작용합니다. 다만 상대 차량의 급정거, 불법 주정차, 후미등 불량 등 특별한 사정이 확인되면 과실비율이 조정될 수 있습니다."},"laws":[{"name":"도로교통법 제19조(안전거리 확보 등)","content":"모든 차의 운전자는 같은 방향으로 가고 있는 앞차의 뒤를 따르는 경우에는 앞차가 갑자기 정지하게 되는 경우 그 앞차와의 충돌을 피할 수 있는 필요한 거리를 확보하여야 한다.","relevance":"본인 차량이 전방 차량과 충분한 안전거리를 확보하지 못하여 추돌한 상황에 직접 적용됩니다.","effect":"안전거리 미확보는 추돌 사고의 핵심 과실 근거로, 후행 차량의 과실 100% 적용의 법적 근거가 됩니다."},{"name":"도로교통법 제48조(안전운전 및 친환경 경제운전의 의무)","content":"모든 차의 운전자는 차의 조향장치·제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"전방 상황을 늦게 인지하여 제동을 늦게 한 행위는 안전운전 의무 위반에 해당합니다.","effect":"안전운전 의무 위반으로 민·형사상 책임의 근거가 되며, 손해배상 과실상계 시 불리하게 작용합니다."},{"name":"도로교통법 제54조(사고 발생 시의 조치)","content":"차의 운전 등 교통으로 인하여 사람을 사상하거나 물건을 손괴한 경우에는 그 차의 운전자나 그 밖의 승무원은 즉시 정차하여 사상자를 구호하는 등 필요한 조치를 하여야 한다.","relevance":"사고 발생 후 적절한 조치 의무를 규정하며, 미조치 시 추가적인 법적 책임이 발생합니다.","effect":"사고 후 미조치 시 뺑소니로 처벌받을 수 있으며, 보험 처리에도 불이익이 발생합니다."}],"cases":[{"title":"동일 방향 진행 중 전방주시 소홀로 인한 추돌 사고","facts":"피고(후행 차량)가 동일 방향으로 진행하던 중 전방 차량의 감속·정차를 늦게 발견하여 제동하였으나 충격을 피하지 못하고 추돌하였고, 피고는 브레이크를 늦게 밟은 사실을 인정하였다.","ruling":"후행 차량(추돌차) 100% : 선행 차량(피추돌차) 0%","reason":"후행 차량 운전자는 전방주시의무 및 안전거리 확보 의무를 부담하며, 전방 차량의 감속·정차는 예견 가능한 상황이므로 후행 차량의 과실이 전부 인정된다. 다만 선행 차량이 급격하고 예측 불가능한 방식으로 정차하였거나 후미등 결함이 있는 경우 선행 차량에 일부 과실이 인정될 수 있다."},{"title":"전방 차량 급정거 시 후행 차량 추돌 사건","facts":"전방 차량이 특별한 이유 없이 급정거하였고, 후행 차량이 이를 늦게 인지하여 추돌이 발생한 사안에서 전방 차량 측이 급정거를 주장하며 과실 분담을 요구하였다.","ruling":"후행 차량 80~90% : 전방 차량 10~20% (급정거 입증 시)","reason":"전방 차량의 급정거가 객관적으로 입증되고 후미등 불량 등 귀책사유가 확인되는 경우에 한하여 선행 차량에 10~20%의 과실이 인정될 수 있다. 단순 감속의 경우에는 후행 차량의 전방주시 의무가 우선되므로 과실 감경이 어렵다."}],"notes":["후행 추돌 사고는 원칙적으로 추돌 차량의 과실 100%가 적용됩니다.","본인이 직접 ''브레이크를 늦게 밟았다''고 진술한 내용은 과실 인정 진술로 활용될 수 있습니다.","상대 차량에 급정거, 후미등 불량, 불법 주정차 등 특수 사정이 있는 경우 과실비율 조정 가능성이 있습니다.","블랙박스 영상, 사고 현장 사진, 목격자 진술 등을 확보해두시는 것이 중요합니다.","사고 경위서 작성 시 브레이크 관련 진술은 신중하게 하시기 바랍니다."],"needed":["사고 당시 블랙박스 영상 (전방 카메라 및 후방 카메라 모두)","상대 차량의 정차·감속 이유 (신호대기, 급정거, 불법 주정차 여부)","사고 발생 도로 유형 (일반도로, 고속도로, 주차장 등)","상대 차량 후미등 정상 작동 여부","사고 당시 날씨 및 노면 상태 (우천, 결빙 등)","사고 발생 시간대 (주간/야간)","충돌 전 양 차량의 속도","상대 차량의 급정거 여부 및 그 이유","인명 피해 및 차량 파손 정도","경찰 사고 사실 확인서 및 보험사 접수 내역"]}'::jsonb, fault_ratio_a = 100, fault_ratio_b = 0, chart_code = '차41-1', summary = '입력자(본인 차량)가 진행 중 전방 차량의 정차 또는 감속을 늦게 인지하여 추돌한 사고입니다. 본인이 브레이크를 늦게 밟아 전방주시의무를 소홀히 한 것이 주된 원인입니다. 구체적인 도로 상황 및 상대 차량의 행동에 대한 추가 정보가 필요합니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = '5eaf15e2-6842-4d6d-bec5-9778b4de5c22';
update posts set analysis = '{"summary":"피해자(본인 차량)가 정차 중인 상태에서 과속한 상대방 차량이 다른 차량을 충격한 후 연쇄적으로 피해차량을 추돌한 사고입니다. 본인은 정차 중으로 사고 회피 가능성이 전혀 없었으며, 경찰 및 구급대가 현장 출동하여 사건이 즉시 접수되었습니다. 과실비율은 상대방 100%, 본인 0%로 확정된 상태입니다.","chartCode":"차42-1","chartName":"선행사고·고장차량 정차 중 추돌","ratio":{"a":{"label":"본인 차량 (정차 중)","percent":0},"b":{"label":"상대 차량 (과속 후 연쇄추돌)","percent":100},"reason":"본인은 정차 중이었으므로 사고 회피 가능성이 전무하며, 상대방이 과속으로 선행 차량을 충격한 후 연쇄적으로 정차 중인 피해차량을 추돌한 사고입니다. 정차 중인 차량에 대한 추돌은 피해차량 과실이 인정되지 않으며, 상대방의 과속 및 전방주시 의무 위반이 사고의 유일한 원인입니다."},"laws":[{"name":"도로교통법 제17조(자동차 등의 속도)","content":"모든 차의 운전자는 제한속도를 준수하여야 하며, 도로 상황에 따라 안전한 속도로 운행하여야 한다.","relevance":"상대방 차량의 과속 운행이 본 사고의 직접적 원인이며, 제한속도 위반은 과실 가중 요인으로 작용합니다.","effect":"과속 위반은 상대방의 과실을 100%로 확정하는 핵심 근거가 됩니다."},{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치, 제동장치, 그 밖의 장치를 정확하게 조작하여야 하며 도로의 교통 상황과 차의 구조·성능에 따라 다른 사람에게 위험과 장해를 주지 아니하는 속도와 방법으로 운전하여야 한다.","relevance":"상대방 차량이 전방 주시 의무를 게을리하고 과속 운행하여 연쇄 추돌을 유발하였습니다.","effect":"안전운전 의무 위반으로 상대방의 손해배상 책임이 전적으로 인정됩니다."},{"name":"민법 제750조(불법행위의 내용)","content":"고의 또는 과실로 인한 위법행위로 타인에게 손해를 가한 자는 그 손해를 배상할 책임이 있다.","relevance":"상대방의 과속 및 안전운전 의무 위반으로 인한 불법행위가 성립하며, 피해자에 대한 모든 손해(재산적·비재산적 손해)를 배상할 의무가 있습니다.","effect":"치료비, 휴업손해, 향후치료비, 위자료 등 모든 손해에 대한 배상청구권이 인정됩니다."}],"cases":[{"title":"정차 중 과속 차량에 의한 연쇄추돌 사고 (서울중앙지법)","facts":"신호 대기 또는 정차 중인 차량을 과속한 차량이 다른 차량을 충격 후 연쇄적으로 추돌한 사안에서, 피해차량 운전자는 정차 상태로 사고 회피 가능성이 없었음.","ruling":"가해차량 100% : 피해차량 0%","reason":"정차 중인 피해차량에게는 어떠한 과실도 인정할 수 없으며, 과속 및 전방주시 태만을 원인으로 한 가해차량의 전적인 책임이 인정됨."},{"title":"과속 연쇄충돌 후 정차차량 추돌 손해배상 사건 (대법원 판례 참조)","facts":"가해차량이 과속으로 선행 충돌 후 관성에 의해 정차 중인 피해차량을 추돌한 사안으로, 피해자는 정차 중 아무런 귀책사유가 없었음.","ruling":"가해차량 100% 과실 인정","reason":"피해차량이 정차 중이었고, 사고 발생에 기여한 어떠한 행위도 없어 피해차량 과실을 0%로 판단. 가해차량의 과속이 사고의 단독 원인으로 인정됨."}],"notes":["현재 상대방 100% 과실이 확정된 상태이므로, 보험사와의 합의 시 치료비·휴업손해·향후치료비·위자료 등 모든 항목을 꼼꼼히 청구하시기 바랍니다.","보험사의 초기 합의 제안은 실제 손해액보다 낮게 제시되는 경우가 많으므로, 치료가 완전히 종결된 후 합의를 진행하는 것이 유리합니다.","경찰 및 구급대가 현장에 출동하여 사건이 접수된 만큼, 사고 경위에 대한 객관적 증거(교통사고 사실확인원, CCTV 영상, 블랙박스 등)를 반드시 확보하시기 바랍니다.","가해차량 차주와 대화가 어렵다면 가해차량 보험사를 통해 모든 절차를 진행하시면 됩니다.","후유장해 가능성이 있는 경우 섣불리 합의하지 마시고 반드시 전문 의료기관에서 충분한 치료 후 장해진단을 받으시기 바랍니다.","합의금 산정 시 적극적 손해(치료비, 향후치료비, 개호비), 소극적 손해(휴업손해, 상실수익), 위자료를 모두 포함하여 청구하십시오."],"needed":["부상 정도 및 진단명 (입원 여부, 진단서 내용)","치료 기간 및 현재 치료 진행 상황","직업 및 월 소득 정보 (휴업손해 산정을 위해)","차량 수리비 또는 전손 여부 및 견적","블랙박스, CCTV 영상 확보 여부","교통사고 사실확인원 발급 여부","상대방 보험사 접촉 여부 및 현재 진행 상황","후유장해 가능성 여부 (정형외과·신경외과 등 전문의 소견)"]}'::jsonb, fault_ratio_a = 0, fault_ratio_b = 100, chart_code = '차42-1', summary = '피해자(본인 차량)가 정차 중인 상태에서 과속한 상대방 차량이 다른 차량을 충격한 후 연쇄적으로 피해차량을 추돌한 사고입니다. 본인은 정차 중으로 사고 회피 가능성이 전혀 없었으며, 경찰 및 구급대가 현장 출동하여 사건이 즉시 접수되었습니다. 과실비율은 상대방 100%, 본인 0%로 확정된 상태입니다.', title = '선행사고 정차 차량 추돌 (차42-1)' where id = '455139e1-d832-45c8-a2a8-e12c4bad2e2f';
update posts set analysis = '{"summary":"피해자(본인)가 횡단보도 앞 보행자 보호를 위해 정차 중, 후행 가해 차량이 브레이크 미조작으로 추돌한 사고입니다. 피해자는 전적으로 법규를 준수한 상태였으며, 가해 차량의 일방적 과실로 발생한 전형적인 추돌 사고입니다. 과실비율 100:0(가해자 전과실)이 인정된 사안입니다.","chartCode":"차41-1","chartName":"동일방향 후행차 추돌(전방주시태만)","ratio":{"a":{"label":"본인 차량 (횡단보도 정차)","percent":0},"b":{"label":"상대 차량 (후행 추돌)","percent":100},"reason":"횡단보도 보행자 보호를 위한 정차는 도로교통법상 적법한 의무 이행 행위이며, 정차 중인 차량을 추돌한 후행 차량은 전방주시의무 및 안전거리 확보의무를 위반한 전과실입니다. 피해자에게 귀책사유가 전혀 없으므로 과실비율 0:100이 적용됩니다."},"laws":[{"name":"도로교통법 제27조(보행자 보호)","content":"모든 차의 운전자는 횡단보도에서 보행자가 횡단하고 있을 때에는 일시정지하여 보행자의 횡단을 방해하거나 위험을 주어서는 아니 된다.","relevance":"피해자의 횡단보도 앞 정차는 본 조항에 따른 적법한 의무 이행이므로, 정차 행위 자체에 과실이 없음을 뒷받침합니다.","effect":"피해자 과실 0% 근거, 가해자의 위법성 강화"},{"name":"도로교통법 제19조(안전거리 확보 및 앞지르기 금지)","content":"모든 차의 운전자는 같은 방향으로 가고 있는 앞차의 뒤를 따르는 경우에는 앞차가 갑자기 정지하게 되는 경우 그 앞차와의 충돌을 피할 수 있는 필요한 거리를 확보하여야 한다.","relevance":"가해 차량이 안전거리를 확보하지 않고 전방주시를 태만히 하여 정차 중인 피해 차량을 추돌한 행위는 본 조항의 직접적 위반입니다.","effect":"가해자 과실 100% 근거, 손해배상 책임 전부 귀속"},{"name":"민법 제750조(불법행위 손해배상)","content":"고의 또는 과실로 인한 위법행위로 타인에게 손해를 가한 자는 그 손해를 배상할 책임이 있다.","relevance":"가해자의 전방주시태만 및 안전거리 미확보 과실로 발생한 물적·인적 손해에 대한 배상 청구의 법적 근거입니다.","effect":"차량 수리비, 치료비, 위자료, 일실수입 등 전 손해항목에 대한 배상 청구 가능"}],"cases":[{"title":"횡단보도 앞 정차 중 후행차량 추돌 사고 (서울중앙지법 2021)","facts":"피해자가 횡단보도 앞 보행자 보호를 위해 정차 중, 후행 차량이 스마트폰 조작 중 전방주시를 게을리하여 추돌. 피해자 경추 염좌 2주 진단.","ruling":"가해자 100 : 피해자 0","reason":"정차 중인 차량에 대한 후방 추돌은 특별한 사정이 없는 한 추돌 차량의 전적인 과실로 판단. 피해자의 정차는 법적 의무 이행으로 과실 없음."},{"title":"신호대기 정차 중 추돌 통원치료 합의 사례 (금융분쟁조정위원회)","facts":"신호대기로 정차 중 후방 추돌, 전치 2주 경추 염좌 진단, 통원 14일 치료. 수리비 100만원대, 대물 합의 후 대인 합의 진행.","ruling":"가해자 100 : 피해자 0, 합의금 130~180만원 수준","reason":"통원 1일당 위자료(교통비 포함) + 치료 기간 일실수입 + 향후치료비 일부를 반영하여 산정. 직업·나이·치료 기간에 따라 편차 발생."}],"notes":["✅ 합의금 구성 항목 안내 (전치 2주 통원 기준 예시): ① 치료비 실비 전액 (보험사 직접 지급 또는 환급), ② 통원 위자료: 1일 5만~8만원 × 통원일수 (14일 기준 약 70~112만원), ③ 일실수입(휴업손해): 아르바이트 소득 입증 시 통원일수×일당, ④ 향후치료비: 추가 치료 예상 시 청구 가능, ⑤ 대물: 수리비 120만원 + 렌트비(수리기간 4일분) 전액 청구 가능","🚗 렌트비 청구 가능: 수리기간 4일 동안 동급 차량 렌트비를 가해자 보험에 청구할 수 있습니다 (통상 1일 5~10만원 수준)","📋 합의 전 주의사항: 전치 2주라도 통원 치료가 길어질 수 있으므로 증상이 완전히 호전된 후 합의하는 것을 강력 권고합니다. 합의 후에는 추가 청구가 불가합니다.","💰 예상 합의금 범위: 치료비 제외 순수 위자료+일실수입 기준 약 100~200만원 수준이나, 치료 기간·아르바이트 소득 증빙·증상 정도에 따라 달라집니다.","📌 시험·아르바이트 일실수입 입증: 아르바이트 계약서, 급여명세서, 학교 시험일정표 등을 보관해두면 일실수입 청구 시 유리합니다.","⚠️ 보험사 초기 합의 제안은 최솟값: 보험사가 조기 합의를 제안할 경우 치료 종결 전 합의하지 말고, 치료가 완료된 후 협의하시기 바랍니다."],"needed":["아르바이트 월 소득 및 근무 계약서 (일실수입 산정에 필요)","실제 통원 횟수 및 치료 종결 여부 (위자료 산정 기준)","차량 렌트 여부 및 렌트비 영수증","향후 치료 필요 여부에 대한 의사 소견서","가해 차량 보험사명 및 담당자 연락처 (협의 진행 여부 확인)"]}'::jsonb, fault_ratio_a = 0, fault_ratio_b = 100, chart_code = '차41-1', summary = '피해자(본인)가 횡단보도 앞 보행자 보호를 위해 정차 중, 후행 가해 차량이 브레이크 미조작으로 추돌한 사고입니다. 피해자는 전적으로 법규를 준수한 상태였으며, 가해 차량의 일방적 과실로 발생한 전형적인 추돌 사고입니다. 과실비율 100:0(가해자 전과실)이 인정된 사안입니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = '12bd2b4e-2146-48fd-a706-93a8bfe13961';
update posts set analysis = '{"summary":"본인 차량이 신호에 따라 좌회전 진행 중, 상대방 차량이 신호를 위반하고 우회전하면서 본인 차량 조수석 문 부위를 충격한 사고입니다. 경찰 수사 결과 상대방의 신호위반(12대 중과실)이 확인되어 불구속 송치되었으며, 분쟁심의위원회에서 상대방 과실 90%로 결정되었습니다.","chartCode":"차3-1","chartName":"신호교차로 좌회전 차량 대 신호위반 우회전 차량","ratio":{"a":{"label":"본인 차량 (좌회전)","percent":10},"b":{"label":"상대 차량 (신호위반 우회전)","percent":90},"reason":"상대방 차량이 신호를 위반하여 우회전한 것이 경찰 블랙박스 분석으로 확인되었고, 신호위반은 12대 중과실에 해당하여 상대방의 책임이 매우 큽니다. 분쟁심의위원회(분심위)에서도 상대방 과실 90%로 최종 결정한 바 있습니다. 본인 차량은 적법한 신호에 따라 좌회전하였으나, 교차로 진입 시 전방 주시 의무 등 일반적 주의의무 위반 가능성이 미미하게 반영되어 10%가 산정됩니다."},"laws":[{"name":"도로교통법 제5조(신호 또는 지시에 따를 의무)","content":"도로를 통행하는 차마의 운전자는 교통안전시설이 표시하는 신호 또는 지시를 따라야 한다.","relevance":"상대방이 신호를 무시하고 우회전하여 본 조항을 위반하였습니다.","effect":"신호위반은 12대 중과실로 분류되며, 피해자 측 과실을 현저히 감소시키는 중요한 법적 근거가 됩니다."},{"name":"도로교통법 제156조(벌칙) 및 제151조(업무상과실)","content":"신호위반 등 12대 중과실로 인한 교통사고는 교통사고처리특례법상 특례 적용이 배제되어 피해자 합의 여부와 무관하게 형사처벌 대상이 됩니다.","relevance":"가해자가 불구속 송치된 것은 신호위반(12대 중과실)이 인정되었기 때문입니다.","effect":"가해자는 형사처벌 대상이 되며, 민사상 손해배상 책임도 가중됩니다."},{"name":"민법 제750조(불법행위의 내용)","content":"고의 또는 과실로 인한 위법행위로 타인에게 손해를 가한 자는 그 손해를 배상할 책임이 있다.","relevance":"신호위반으로 인한 충돌 사고에서 가해자의 불법행위에 따른 손해배상 의무가 발생합니다.","effect":"수리비 350만 원을 포함한 손해(수리비, 위자료 등)에 대해 과실비율에 따라 배상 청구가 가능합니다."}],"cases":[{"title":"신호교차로 좌회전 차량 대 신호위반 우회전 차량 충돌 사건","facts":"피해 차량이 좌회전 신호에 따라 교차로를 좌회전하던 중, 상대 차량이 신호를 위반하고 우회전하면서 피해 차량 측면을 충격한 사안.","ruling":"가해 차량(신호위반) 90% : 피해 차량(좌회전) 10%","reason":"신호위반은 12대 중과실로서 교통사고처리특례법상 가중 책임이 인정되며, 적법하게 신호에 따라 진행한 피해 차량의 과실은 최소한으로 제한됩니다. 분쟁심의위원회의 결정 역시 동일한 기준을 적용한 것으로 봅니다."},{"title":"교차로 신호위반 우회전 차량 충돌 관련 손해배상 청구 사건","facts":"신호를 위반한 우회전 차량이 정상 신호에 따라 진행하던 좌회전 차량의 측면을 충격하여 차량 수리비 및 위자료 청구가 이루어진 사안.","ruling":"가해 차량 90% : 피해 차량 10% (분쟁심의위원회 기준 적용)","reason":"신호위반 차량의 과실이 압도적으로 크며, 피해 차량은 신호를 준수하여 진행하였으므로 과실이 최소화됩니다. 수리비 전액에 대해 과실비율에 따른 배상이 인정됩니다."}],"notes":["분쟁심의위원회(분심위)에서 이미 상대방 과실 90%로 결정되었으므로, 이 결정을 근거로 보험사와 합의 또는 민사 소송 진행이 가능합니다.","신호위반(12대 중과실)은 교통사고처리특례법 제3조 제2항 단서에 해당하여 합의 여부와 무관하게 형사처벌이 가능하며, 이는 민사 협상에서도 유리한 근거가 됩니다.","수리비 350만 원 중 본인 과실 10%를 제외한 315만 원은 상대방 보험사로부터 청구 가능합니다.","보험사가 분심위 결정(90:10)보다 낮은 비율을 고집할 경우, 금융감독원 민원 또는 법원 소액심판 절차를 통해 추가 청구가 가능합니다.","상해가 있는 경우 치료비, 위자료, 휴업손해 등 추가 손해배상 청구도 검토하시기 바랍니다."],"needed":["상대방 보험사의 최종 입장 및 합의 제시 금액","본인 차량 블랙박스 영상 확보 여부","사고 당시 신호 체계(좌회전 전용 신호 여부, 비보호 좌회전 여부)","상해 발생 여부 및 치료 내역","상대방 보험 가입 여부 및 보험사 처리 현황"]}'::jsonb, fault_ratio_a = 10, fault_ratio_b = 90, chart_code = '차3-1', summary = '본인 차량이 신호에 따라 좌회전 진행 중, 상대방 차량이 신호를 위반하고 우회전하면서 본인 차량 조수석 문 부위를 충격한 사고입니다. 경찰 수사 결과 상대방의 신호위반(12대 중과실)이 확인되어 불구속 송치되었으며, 분쟁심의위원회에서 상대방 과실 90%로 결정되었습니다.', title = '좌회전 신호 중 신호위반 직진 충돌 (차3-1)' where id = 'e649f858-d6ad-44fa-90a9-9294da901a31';
update posts set analysis = '{"summary":"본인 차량이 정차 또는 주행 중 상대 차량에 의해 후방 추돌된 사고입니다. 과실비율은 100:0으로 본인(피해자)의 과실이 전혀 없는 전형적인 후방추돌 사고입니다. 상대방은 책임보험만 가입되어 있어 대인 한도 120만원 초과분에 대해 본인 보험의 무보험차상해 특약 활용이 필요한 상황입니다.","chartCode":"차41-1","chartName":"동일방향 후행차 추돌(전방주시태만)","ratio":{"a":{"label":"본인 차량 (피추돌·정차 또는 주행)","percent":0},"b":{"label":"상대 차량 (후방추돌)","percent":100},"reason":"후방에서 추돌한 차량은 원칙적으로 100% 과실입니다. 선행 차량(본인)이 정상 주행 또는 정차 중이었으므로 피해자 과실은 0%입니다. 가해자가 ''경미한 사고''라고 주장하더라도 과실비율 자체는 변하지 않으며, 부상 정도와 치료 필요성은 별개의 문제입니다."},"laws":[{"name":"도로교통법 제19조(안전거리 확보 등)","content":"모든 차의 운전자는 같은 방향으로 가고 있는 앞차의 뒤를 따르는 경우 앞차가 갑자기 정지하게 되는 경우 그 앞차와의 충돌을 피할 수 있는 필요한 거리를 확보하여야 한다.","relevance":"후방추돌 가해차량(상대방)이 안전거리를 확보하지 않아 발생한 사고로, 본 조항 위반에 해당합니다.","effect":"안전거리 미확보는 가해자의 과실을 100%로 확정하는 핵심 근거이며, 형사처벌(교통사고처리특례법) 및 민사 손해배상 책임의 기초가 됩니다."},{"name":"교통사고처리특례법 제3조(처벌의 특례)","content":"차의 운전자가 교통사고로 인하여 피해자를 상해에 이르게 한 경우, 피해자의 명시적 의사에 반하여 공소를 제기할 수 없다. 단, 종합보험 미가입(책임보험만 가입) 시 반의사불벌 특례 적용이 배제되어 형사처벌 대상이 됩니다.","relevance":"상대방이 책임보험만 가입한 경우, 피해자가 처벌을 원하면 형사입건이 가능합니다. 이는 합의 협상에서 피해자에게 유리한 카드가 됩니다.","effect":"종합보험 미가입 가해자는 피해자가 고소·처벌불원서 미제출 시 형사처벌(벌금·금고)을 받을 수 있으므로, 합의금 협상 시 피해자에게 실질적 협상력이 생깁니다."},{"name":"상법 제724조(보험자와 제3자의 관계) 및 자동차손해배상보장법 제5조","content":"책임보험(의무보험) 대인 한도는 사망 1억5천만원, 부상 등급별 최대 3천만원(1급 기준)이며 실제 한도는 부상등급에 따라 결정됩니다. 한도 초과분은 가해자 개인이 배상해야 합니다.","relevance":"상대방 책임보험 대인 한도가 치료비를 충당하지 못할 경우, 본인 보험의 무보험차상해 특약으로 보전받을 수 있습니다.","effect":"무보험차상해 특약을 통해 치료비·위자료·휴업손해 등을 자신의 보험사로부터 보상받은 후, 보험사가 가해자에게 구상권을 행사합니다."}],"cases":[{"title":"후방추돌 경상 피해자의 손해배상 및 형사처리 사례","facts":"피해 차량이 신호대기 또는 정상 주행 중 후방 차량이 추돌하여 전치 2주 경추 염좌 등 부상. 가해차량은 책임보험만 가입. 가해자는 ''경미한 사고''라며 합의를 종용.","ruling":"과실비율 가해자 100% : 피해자 0%","reason":"법원 및 손해보험협회 기준 모두 후방추돌은 특별한 사정(피해차량의 급제동·무단횡단 등)이 없는 한 추돌차량 100% 과실로 판단합니다. 전치 2주 진단은 경미하더라도 정당한 치료권이 보장되며, 가해자의 ''경미한 사고'' 주장은 법적으로 과실비율이나 치료권에 영향을 미치지 않습니다."},{"title":"책임보험 한도 초과 시 무보험차상해 적용 사례","facts":"가해차량 책임보험만 가입, 대인 한도 120만원(부상 14급 기준) 초과 치료비 발생. 피해자가 자신의 무보험차상해 특약으로 초과분 청구.","ruling":"무보험차상해 특약에서 한도 내 보상 인정","reason":"책임보험 한도 내에서는 가해자 보험사가 보상하고, 초과분은 피해자 본인 보험의 무보험차상해(또는 자기신체손해)로 처리합니다. 이후 피해자 보험사가 가해자에게 구상권을 행사하므로 피해자의 보험료 할증은 없습니다."}],"notes":["책임보험 대인 부상 한도는 부상 등급에 따라 다릅니다. 전치 2주 경추 염좌는 통상 12~14급으로 분류되며 한도가 낮을 수 있으므로, 병원에서 정확한 진단명과 상해등급 확인이 필요합니다.","경찰에 교통사고를 접수하면 가해자는 형사처벌 대상이 됩니다(종합보험 미가입이므로 반의사불벌 특례 미적용). 이는 피해자에게 합의 협상에서 중요한 레버리지가 됩니다.","가해자가 ''경미한 사고''라고 주장해도 진단서와 치료기록이 있으면 정당한 치료비·위자료를 청구할 수 있습니다. 가해자 주장은 법적 효력이 없습니다.","무보험차상해 특약 활용 시 피해자 본인의 보험료 할증이 발생하지 않습니다(가해자 귀책 사고). 보험사가 가해자에게 구상권 행사.","치료 종결 후 합의 시 향후 치료비, 위자료, 휴업손해 등을 종합하여 청구하는 것이 유리합니다. 치료 중 성급한 합의는 피하시기 바랍니다.","형사합의금과 민사 손해배상은 별개입니다. 형사처벌 불원서(처벌을 원하지 않는다는 합의)를 써주는 대가로 추가 합의금을 받을 수 있습니다."],"needed":["정확한 사고 경위(본인 차량 정차 중인지, 주행 중인지)","병원 진단서상 부상 등급 및 진단명 확인","책임보험 대인 한도 정확한 금액 확인 (부상 등급별 한도표 기준)","본인 보험 무보험차상해 특약 가입 여부 및 한도 확인","경찰 사고접수 여부 및 가해자 형사처리 진행 여부","향후 치료 계획 및 예상 치료비 규모"]}'::jsonb, fault_ratio_a = 0, fault_ratio_b = 100, chart_code = '차41-1', summary = '본인 차량이 정차 또는 주행 중 상대 차량에 의해 후방 추돌된 사고입니다. 과실비율은 100:0으로 본인(피해자)의 과실이 전혀 없는 전형적인 후방추돌 사고입니다. 상대방은 책임보험만 가입되어 있어 대인 한도 120만원 초과분에 대해 본인 보험의 무보험차상해 특약 활용이 필요한 상황입니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = 'dff2f2ed-3e27-4c37-9924-b0756787882e';
update posts set analysis = '{"summary":"오토바이(본인) 주행 중 후방에서 상대방 오토바이가 추돌한 사고입니다. 분쟁조정위원회(분심위)에서 이미 100:0(상대방 100% 과실)으로 결정된 사안입니다. 상대방은 형사처분(벌금 70만원)까지 종결된 상태이며, 양측 모두 삼성화재 가입으로 동일 보험사 처리 중입니다.","chartCode":"차41-1","chartName":"동일방향 후행추돌(전방주시태만)","ratio":{"a":{"label":"본인 차량 (피추돌 오토바이)","percent":0},"b":{"label":"상대 차량 (추돌 오토바이)","percent":100},"reason":"후방에서 일방적으로 추돌한 경우 추돌 차량의 전방주시태만·안전거리 미확보가 전적인 원인입니다. 분쟁조정위원회 역시 100:0으로 상대방 전과실을 인정하였으며, 형사 처분(벌금)까지 확정된 사안입니다. 피추돌 차량(본인)에게는 귀책 사유가 없습니다."},"laws":[{"name":"도로교통법 제19조(안전거리 확보 등)","content":"모든 차의 운전자는 같은 방향으로 가고 있는 앞차의 뒤를 따르는 경우에는 앞차가 갑자기 정지하게 되는 경우 그 앞차와의 충돌을 피할 수 있는 필요한 거리를 확보하여야 한다.","relevance":"상대방 오토바이가 안전거리를 확보하지 않아 추돌이 발생한 직접적 근거 조항입니다.","effect":"안전거리 미확보 위반 시 과태료·벌점 부과 및 민사상 손해배상 전액 책임의 근거가 됩니다."},{"name":"도로교통법 제48조(안전운전 및 친환경 경제운전의 의무)","content":"모든 차의 운전자는 차의 조향장치와 제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"전방주시 소홀 및 제동 미흡으로 추돌을 야기한 상대방 운전자의 안전운전 의무 위반에 해당합니다.","effect":"안전운전 의무 위반은 형사처벌(벌금) 및 민사 손해배상 책임의 근거가 됩니다."},{"name":"민법 제750조(불법행위의 내용)","content":"고의 또는 과실로 인한 위법행위로 타인에게 손해를 가한 자는 그 손해를 배상할 책임이 있다.","relevance":"상대방의 과실로 본인에게 발생한 신체적·재산적 손해 전부에 대한 배상 청구의 법적 근거입니다.","effect":"치료비, 휴업손해, 위자료, 오토바이 수리비 등 모든 손해에 대해 상대방(및 보험사)에 청구 가능합니다."}],"cases":[{"title":"이륜차 동일방향 후방추돌 사고 과실비율 (서울중앙지법)","facts":"신호대기 중이던 오토바이를 뒤따르던 오토바이가 전방주시 소홀로 추돌하여 피해자에게 골절 등 상해를 입힌 사안.","ruling":"가해차량(추돌) 100% : 피해차량 0%","reason":"피해 차량이 갑작스러운 급정거 등 특별한 과실이 없는 한 후방 추돌 사고의 과실은 추돌 차량에 전적으로 귀속되며, 분쟁조정위원회 결정과 형사 확정 처분도 동일한 결론을 지지한다고 판단."},{"title":"금융분쟁조정위원회 이륜차 추돌 과실비율 조정 사례","facts":"동일 방향 진행 중 선행 오토바이를 후행 오토바이가 추돌, 피해자 측 특별 과실(급차로변경, 급제동 등) 없음. 양측 동일 보험사 가입.","ruling":"후행(추돌) 차량 100% 과실 인정","reason":"후행 차량 운전자의 안전거리 미확보 및 전방주시태만이 사고의 유일한 원인으로, 피해자에게 기여 과실이 없다고 결정. 동일 보험사 가입 여부는 과실 비율 판단에 영향 없음."}],"notes":["분쟁조정위원회(분심위) 100:0 결정은 보험사 합의 및 소송에서 강력한 근거 자료로 활용됩니다.","상대방 형사처분(벌금 70만원) 확정은 민사 손해배상 청구 시 상대방 과실 입증에 유리하게 작용합니다.","양측 동일 보험사(삼성화재)인 경우 이해충돌 우려가 있으므로, 보상 진행 중 불리한 처리가 있다면 금융감독원에 민원 제기 또는 변호사 선임을 고려하시기 바랍니다.","대인 보상(치료비·위자료·휴업손해 등)은 상대방 책임보험 및 종합보험에서 청구하며, 부족분은 본인 무보험차상해 특약으로 보전 가능합니다.","오토바이 수리비(대물) 역시 상대방 보험에서 전액 청구 가능합니다.","사고 후 후유증이 있다면 치료 종결 전 합의를 서두르지 말고 향후 치료비·후유장해까지 포함하여 협의하시기 바랍니다."],"needed":["본인 오토바이의 급제동·급차로변경 등 특이 운전 행동 여부 (과실 감경 요소 검토 필요)","사고 당시 블랙박스·CCTV 영상 확보 여부","현재 치료 진행 상황 및 진단명(후유장해 여부)","대인 보상 중 구체적으로 분쟁이 발생한 항목(치료비·휴업손해·위자료 등)","본인 보험의 무보험차상해·자기신체사고 특약 가입 여부"]}'::jsonb, fault_ratio_a = 0, fault_ratio_b = 100, chart_code = '차41-1', summary = '오토바이(본인) 주행 중 후방에서 상대방 오토바이가 추돌한 사고입니다. 분쟁조정위원회(분심위)에서 이미 100:0(상대방 100% 과실)으로 결정된 사안입니다. 상대방은 형사처분(벌금 70만원)까지 종결된 상태이며, 양측 모두 삼성화재 가입으로 동일 보험사 처리 중입니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = 'fe295a31-74e4-4085-97be-8850d1425707';
update posts set analysis = '{"summary":"본인 차량이 유턴 신호를 받고 유턴을 시행하던 중, 상대방 차량이 우회전 후 직진하면서 본인 차량의 뒷문과 뒷휀더 부위를 충격한 사고입니다. 유턴 신호가 있었으나 상대방의 우회전 후 직진 차량과의 교차 지점에서 충돌이 발생하였습니다. 피해 부위(뒷문·뒷펜더)로 보아 본인 차량이 유턴을 거의 완료하는 시점에 충격을 받은 것으로 추정됩니다.","chartCode":"차7-1","chartName":"신호교차로 유턴 차량 대 직진 차량 충돌","ratio":{"a":{"label":"본인 차량 (유턴)","percent":30},"b":{"label":"상대 차량 (우회전 후 직진)","percent":70},"reason":"본인 차량은 유턴 신호를 적법하게 받아 유턴을 진행하였으므로 기본 과실이 낮습니다. 그러나 유턴 차량은 유턴 완료 전까지 교차로 내 다른 차량의 통행을 방해하지 않아야 할 주의의무가 있습니다. 상대방은 우회전 후 직진 과정에서 전방 주시 및 속도 조절 의무를 위반하였고, 피해 부위가 본인 차량의 후방(뒷문·뒷펜더)인 점을 고려하면 상대방의 과실이 더 크다고 판단됩니다."},"laws":[{"name":"도로교통법 제25조(교차로 통행방법)","content":"모든 차마의 운전자는 교차로에서 우회전이나 좌회전을 할 때에는 미리 도로의 우측 가장자리 또는 중앙으로 붙어 서행하여야 하며, 다른 차마의 정상 통행을 방해해서는 안 된다.","relevance":"유턴 및 우회전 후 직진 차량 모두 교차로 내 통행방법을 준수해야 할 의무가 있습니다.","effect":"교차로 통행방법 위반 시 과실 가중 요인이 됩니다."},{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치와 제동장치, 그 밖의 장치를 정확히 조작하여야 하며, 도로의 교통상황과 차의 구조·성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"상대방 차량이 우회전 후 직진 시 전방 주시 및 속도 조절 의무를 다하지 않은 점에 적용됩니다.","effect":"안전운전 의무 위반으로 상대방 과실 가중의 근거가 됩니다."},{"name":"도로교통법 제5조(신호 또는 지시에 따를 의무)","content":"도로를 통행하는 보행자와 차마의 운전자는 교통안전시설이 표시하는 신호 또는 지시를 따라야 한다.","relevance":"본인 차량은 유턴 신호에 따라 적법하게 유턴을 진행하였으므로, 신호 준수 사실이 본인의 과실을 낮추는 근거가 됩니다.","effect":"신호 준수 여부가 과실 산정의 핵심 기준이 됩니다."}],"cases":[{"title":"유턴 신호 차량 대 우회전 후 직진 차량 충돌 사례","facts":"피해 차량이 유턴 신호에 따라 유턴을 진행하던 중, 가해 차량이 우회전 후 직진하면서 유턴 차량의 측면 후방을 충격한 사고.","ruling":"유턴 차량 30% : 직진 차량 70%","reason":"유턴 신호를 받아 적법하게 진행한 유턴 차량의 과실은 낮으나, 유턴 시 주변 차량 확인 의무 미이행에 따라 일부 과실 인정. 우회전 후 직진 차량은 교차로 진입 후 전방 주시·속도 조절 의무 위반으로 주된 과실 인정."},{"title":"교차로 내 유턴 완료 단계 차량 추돌 사례","facts":"유턴을 거의 완료한 차량의 후방부(뒷문·뒷펜더)를 후행 직진 차량이 충격한 사건으로, 피해차량이 유턴 신호를 준수하였음이 확인됨.","ruling":"유턴 차량 20~30% : 직진 차량 70~80%","reason":"유턴 완료 단계에서의 충격은 직진 차량의 전방 주시 불이행이 주된 원인으로, 유턴 차량의 과실은 상대적으로 낮게 산정됨."}],"notes":["피해 부위가 본인 차량의 뒷문·뒷펜더인 점은 유턴이 거의 완료된 시점에 충격을 받은 것으로 해석되어 본인 과실을 낮추는 중요한 요소입니다.","유턴 신호 존재 여부가 과실 산정의 핵심이므로, 신호등 영상·블랙박스 영상 확보가 필수적입니다.","상대방이 우회전 후 직진 과정에서 교차로 내 다른 차량을 충분히 확인하지 못한 점이 주요 과실로 작용합니다.","최종 과실비율은 블랙박스 영상, 목격자 진술, 현장 CCTV 등 구체적 증거에 따라 달라질 수 있습니다."],"needed":["유턴 신호등 존재 여부 및 신호 주기 확인 (유턴 전용 신호인지 여부)","블랙박스 영상 (본인 차량 및 상대방 차량 모두)","교차로 CCTV 영상","충돌 당시 상대방 차량의 정확한 속도","상대방 차량의 우회전 완료 시점 및 위치","도로 차선 구조 및 유턴 허용 구간 확인","목격자 진술서"]}'::jsonb, fault_ratio_a = 30, fault_ratio_b = 70, chart_code = '차7-1', summary = '본인 차량이 유턴 신호를 받고 유턴을 시행하던 중, 상대방 차량이 우회전 후 직진하면서 본인 차량의 뒷문과 뒷휀더 부위를 충격한 사고입니다. 유턴 신호가 있었으나 상대방의 우회전 후 직진 차량과의 교차 지점에서 충돌이 발생하였습니다. 피해 부위(뒷문·뒷펜더)로 보아 본인 차량이 유턴을 거의 완료하는 시점에 충격을 받은 것으로 추정됩니다.', title = '본인 차량이 유턴 신호를 받고 유턴을 시행하던 중,' where id = 'fed0d94a-f2f7-4920-b753-26491f446e0d';
update posts set analysis = '{"summary":"2025년 3월 17일, 본인 차량이 정차 중 상대방 차량이 후진하여 충돌한 사고입니다. 상대방 차량의 후진 과정에서 발생한 사고로, 본인 차량은 정차 상태였습니다. 입원 및 지속적인 물리치료와 신경차단술이 진행 중인 상황입니다.","chartCode":"차41-1","chartName":"동일방향 후행추돌(전방주시태만/후진 충돌)","ratio":{"a":{"label":"본인 차량 (정차)","percent":0},"b":{"label":"상대 차량 (후진)","percent":100},"reason":"상대방 차량이 후진 중 정차해 있던 본인 차량을 충돌한 사고로, 후진 차량의 전적인 과실입니다. 도로교통법상 후진 시 다른 차량의 통행을 방해하지 않을 의무가 있으며, 정차 중인 차량에는 과실이 없습니다. 따라서 과실비율은 상대방 100%, 본인 0%가 원칙입니다."},"laws":[{"name":"도로교통법 제18조(횡단 등의 금지)","content":"모든 차의 운전자는 후진 시 다른 차의 정상적인 통행을 방해할 우려가 있을 때에는 후진하여서는 아니 된다.","relevance":"상대방 차량이 후진하면서 정차 중인 본인 차량을 충돌한 행위에 직접 적용됩니다.","effect":"후진 차량의 전적인 과실이 인정되며, 피해 차량에 대한 손해배상 책임이 발생합니다."},{"name":"도로교통법 제19조(안전거리 확보 등)","content":"모든 차의 운전자는 같은 방향으로 가고 있는 앞차의 뒤를 따르는 때에는 앞차가 갑자기 정지하게 되는 경우 그 앞차와의 충돌을 피할 수 있는 필요한 거리를 확보하여야 한다.","relevance":"후진 차량은 후방 차량과의 안전거리를 확보하고 후방을 충분히 확인해야 할 의무가 있습니다.","effect":"안전거리 미확보 및 후방 확인 불이행으로 인한 과실 책임이 상대방에게 귀속됩니다."},{"name":"민법 제750조(불법행위의 내용)","content":"고의 또는 과실로 인한 위법행위로 타인에게 손해를 가한 자는 그 손해를 배상할 책임이 있다.","relevance":"상대방의 과실 있는 후진 행위로 인해 본인 및 남편이 상해를 입었으므로 손해배상 청구의 근거가 됩니다.","effect":"치료비, 입원비, 신경차단술 비용, 위자료, 휴업손해 등 모든 손해에 대한 배상을 청구할 수 있습니다."}],"cases":[{"title":"후진 차량 충돌로 인한 과실비율 사건","facts":"피해 차량이 정차 중이던 상황에서 앞서 있던 차량이 후진하여 충돌, 탑승자 2명이 경추 및 요추 부위 상해를 입고 입원 치료를 받은 사례","ruling":"가해 차량(후진) 100% : 피해 차량(정차) 0%","reason":"정차 중인 차량은 충돌 회피 의무가 없으며, 후진 차량은 후방 안전 확인 의무를 다하지 못한 전적인 과실이 인정됨. 탑승자 전원에 대한 치료비 및 위자료 배상 책임이 가해 차량에 귀속됨."},{"title":"후진 추돌 사고 동승자 보상 사건","facts":"차량 내 동승자가 후진 추돌 사고로 경추 염좌, 신경 압박 증상 등으로 신경차단술 및 장기 물리치료를 받은 사례","ruling":"가해 차량 100% 과실 인정, 동승자 포함 전 탑승자에 대한 손해배상 인정","reason":"동승자도 피해자로서 가해 차량 보험사에 직접 치료비 및 위자료를 청구할 수 있으며, 신경차단술 등 적극적 치료에 대한 비용도 배상 범위에 포함됨."}],"notes":["본인과 남편 모두 피해자로서 상대방 보험사에 치료비, 입원비, 신경차단술 비용, 위자료, 휴업손해 전액 청구 가능합니다.","남편의 ''팔 힘빠짐'' 증상(응급실 내원)은 사고와의 인과관계를 명확히 입증하는 것이 중요하며, 신경과 전문의 소견서를 확보하시기 바랍니다.","신경차단술(차단술)은 치료 필요성이 인정되면 보험사에서 전액 지급해야 하나, 일부 보험사가 횟수 제한을 주장할 수 있으므로 의사 소견서를 반드시 보관하세요.","치료가 장기화되고 있으므로 향후 치료비(추정액) 및 후유장해 가능성도 검토하여 합의 시 반영해야 합니다.","합의는 치료 종결 후 진행하는 것을 강력히 권장합니다. 조기 합의 시 향후 치료비를 보상받기 어렵습니다.","남편의 차단술 시행 횟수(다수)와 팔 신경 증상을 고려할 때, 경추 신경 손상 가능성이 있으므로 MRI 정밀 검사 결과를 반드시 확보하세요."],"needed":["사고 당시 블랙박스 영상 또는 CCTV 영상 (후진 사실 입증용)","사고 접수된 경찰 교통사고 사실확인원","상대방 차량 보험사 접수 번호 및 담당자 정보","남편의 팔 힘빠짐 관련 신경과·정형외과 정밀 검사 결과(MRI 등)","치료 중인 병원의 진단서 및 향후 치료 소견서","사고 발생 장소(주차장 내부 여부, 일반도로 여부) 확인","현재 치료 중인 의료기관 명칭 및 치료 기록 일체","본인의 직업 및 소득 관련 자료(휴업손해 산정을 위해)"]}'::jsonb, fault_ratio_a = 0, fault_ratio_b = 100, chart_code = '차41-1', summary = '2025년 3월 17일, 본인 차량이 정차 중 상대방 차량이 후진하여 충돌한 사고입니다. 상대방 차량의 후진 과정에서 발생한 사고로, 본인 차량은 정차 상태였습니다. 입원 및 지속적인 물리치료와 신경차단술이 진행 중인 상황입니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = 'bbf71140-71f6-4e95-9906-29f3bab8dc86';
update posts set analysis = '{"summary":"편도 2차선이 4차선으로 확장되는 구간에서, 본인 차량은 1차선을 유지하며 진행 중 상대 차량이 2차선에서 깜빡이 없이 1차선으로 무단 차선변경을 시도하여 본인 차량 측면을 추돌한 사고입니다. 본인은 경적을 울리며 회피 시도를 하였으나 상대 차량이 계속 진입하여 접촉이 발생하였습니다. 상대 차량의 방향지시등 미사용 및 안전 미확인이 주요 과실 원인입니다.","chartCode":"차42-2","chartName":"진로변경 중 추돌(차선변경 차량 과실)","ratio":{"a":{"label":"본인 차량 (직진 차선유지)","percent":10},"b":{"label":"상대 차량 (무신호 차선변경)","percent":90},"reason":"상대 차량은 방향지시등을 사용하지 않고 무단으로 차선을 변경하였으며, 본인 차량이 경적으로 경고하였음에도 진입을 강행하여 추돌을 유발한 주된 과실이 있습니다. 본인 차량은 차선을 유지하며 주행 중이었으나, 도로 확장 구간에서의 전방주시 의무 소홀 가능성이 소폭 반영됩니다. 방향지시등 미사용은 도로교통법 위반으로 상대방의 과실을 가중시키는 핵심 요소입니다."},"laws":[{"name":"도로교통법 제19조(안전거리 확보 등)","content":"모든 차의 운전자는 차의 진로를 변경하려는 경우 그 변경하려는 방향의 후방에서 오는 차의 정상적인 통행에 장애를 줄 우려가 있을 때에는 진로를 변경하여서는 아니 된다.","relevance":"상대 차량이 본인 차량의 정상 주행을 방해하며 차선변경을 강행한 행위에 직접 적용됩니다.","effect":"차선변경 차량의 과실 가중 및 손해배상 책임 인정 근거"},{"name":"도로교통법 제38조(차의 신호)","content":"모든 차의 운전자는 좌우로 진로를 바꾸려고 하는 때에는 손이나 방향지시기 또는 등화로써 그 행위가 끝날 때까지 신호를 하여야 한다.","relevance":"상대 차량이 방향지시등 없이 차선변경을 시도한 행위는 본 조항을 위반한 것으로, 과실 판단의 핵심 근거가 됩니다.","effect":"방향지시등 미사용은 상대방 과실을 10~20% 추가 가중하는 요소로 작용"},{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차를 운전할 때 전방을 주시하고 안전하게 운전하여야 한다.","relevance":"상대 차량이 옆 차로 차량 유무를 확인하지 않고 차선변경을 강행한 행위에 적용됩니다.","effect":"안전의무 위반으로 손해배상 책임의 주된 근거로 활용"}],"cases":[{"title":"차선변경 차량 방향지시등 미사용 측면 접촉 사고","facts":"피해차량이 직진 차선을 정상 주행 중, 가해차량이 방향지시등 없이 인접 차선에서 급격히 차선변경을 시도하여 피해차량 측면과 접촉한 사안","ruling":"가해차량(차선변경) 90 : 피해차량(직진) 10","reason":"차선변경 차량은 방향지시등 미사용, 후방 및 측방 안전 미확인의 과실이 인정되고, 직진 차량은 회피 가능성이 제한적이었으나 전방주시 의무가 일부 인정되어 10% 과실이 배정됨"},{"title":"도로 확장 구간 합류 시 차선변경 충돌 사고","facts":"2차선에서 4차선으로 확장되는 구간에서 기존 2차선 차량이 안전 확인 없이 1차선으로 합류를 시도하다 직진 중인 1차선 차량과 충돌한 사안","ruling":"차선변경 차량 85~90 : 직진 차량 10~15","reason":"도로 확장 구간이더라도 차선변경 차량은 안전 확인 의무와 방향지시등 사용 의무를 이행해야 하며, 이를 위반한 경우 주된 과실이 인정됨. 경적 울림 등 피해차량의 회피 시도가 입증된 경우 피해차량 과실은 최소화됨"}],"notes":["방향지시등 미사용 사실은 블랙박스 영상으로 입증하는 것이 매우 중요합니다.","경적을 울렸음에도 상대방이 진입을 강행한 정황이 영상으로 확인되면 본인 과실은 10% 이하로 낮아질 수 있습니다.","도로 확장 구간에서의 합류 시 차선변경 의무는 일반 차선변경과 동일하게 적용됩니다.","상대방이 무과실을 주장할 경우, 블랙박스 영상·목격자 진술·도로 CCTV가 핵심 증거가 됩니다.","보험사 과실 협의 시 도표 차42-2 또는 차43 계열 기준이 적용될 수 있으므로, 해당 도표 기준 과실비율을 숙지하시기 바랍니다."],"needed":["블랙박스 영상(전방 및 측방 영상 확인 필수)","사고 발생 지점의 도로 CCTV 영상","상대 차량의 방향지시등 사용 여부에 대한 명확한 영상 증거","사고 당시 경적 울림 시점과 상대 차량 진입 시점의 시간적 간격 확인","목격자 진술 또는 동승자 진술","사고 후 차량 파손 부위(접촉 위치) 사진 및 감정 자료","상대방 보험사의 주장 내용 및 제시 과실비율 확인"]}'::jsonb, fault_ratio_a = 10, fault_ratio_b = 90, chart_code = '차42-2', summary = '편도 2차선이 4차선으로 확장되는 구간에서, 본인 차량은 1차선을 유지하며 진행 중 상대 차량이 2차선에서 깜빡이 없이 1차선으로 무단 차선변경을 시도하여 본인 차량 측면을 추돌한 사고입니다. 본인은 경적을 울리며 회피 시도를 하였으나 상대 차량이 계속 진입하여 접촉이 발생하였습니다. 상대 차량의 방향지시등 미사용 및 안전 미확인이 주요 과실 원인입니다.', title = '급 진로변경 끼어들기 사고 (차42-2)' where id = 'c7a9b7da-c58f-4f87-a2a3-4be69ee46686';
update posts set analysis = '{"summary":"내리막길 신호 정차 중 후방 차량이 조수석 물건을 집으려다 브레이크에서 발을 떼어 본인 차량 후미를 추돌한 사고입니다. 상대방 보험사 담당자도 현장에서 100:0을 인정하였으며, 이는 전형적인 후행 추돌 사고에 해당합니다. 상대방 차주가 대인 접수를 거부하고 있어 추가 조치가 필요한 상황입니다.","chartCode":"차41-1","chartName":"동일방향 후행 추돌 (전방주시태만)","ratio":{"a":{"label":"본인 차량 (정차 중)","percent":0},"b":{"label":"상대 차량 (후미추돌)","percent":100},"reason":"신호에 의해 정차 중인 차량을 후방 차량이 운전 부주의(조수석 물건 수거 중 브레이크 발 이탈)로 추돌하였으므로 상대방 과실 100%입니다. 내리막길이라는 도로 조건에서 중립 기어 상태로 정차한 점은 상대방의 안전 운전 의무 위반을 더욱 명확히 합니다. 정차 중인 피해 차량에게는 귀책 사유가 전혀 없습니다."},"laws":[{"name":"도로교통법 제19조(안전거리 확보 등)","content":"모든 차의 운전자는 같은 방향으로 가고 있는 앞차의 뒤를 따르는 때에는 앞차가 갑자기 정지하게 되는 경우 그 앞차와의 충돌을 피할 수 있는 필요한 거리를 확보하여야 한다.","relevance":"상대방 차량이 정차 중인 본인 차량과의 안전거리를 확보하지 못한 채 브레이크에서 발을 떼어 추돌한 행위에 직접 적용됩니다.","effect":"안전거리 미확보 및 전방주시 의무 위반으로 상대방의 100% 과실 근거가 됩니다."},{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치와 제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"운전 중 조수석 물건을 집으려다 브레이크에서 발을 떼는 행위는 안전운전 의무를 명백히 위반한 것입니다.","effect":"상대방의 전방주시 태만 및 제동장치 부적절 조작에 따른 민·형사상 책임의 근거가 됩니다."},{"name":"상법 제724조(보험자의 직접청구권)","content":"피해자는 보험자에게 직접 보험금 지급을 청구할 수 있다. 보험자는 피보험자가 책임을 질 사고로 인한 손해에 대해 피해자에게 직접 보상할 의무가 있다.","relevance":"차주가 대인 접수를 거부하더라도 피해자는 상대방 보험사에 직접 보험금(대인)을 청구할 법적 권리가 있습니다.","effect":"차주 동의 없이도 상대방 보험사에 직접 대인 청구가 가능하며, 보험사는 이를 거절할 수 없습니다."}],"cases":[{"title":"정차 중 후방 차량 부주의 추돌 사건 (서울중앙지법)","facts":"신호 대기로 정차 중인 차량을 후방 차량 운전자가 차 내부 물건을 조작하다 브레이크에서 발을 떼어 추돌한 사고로, 피해자는 경추 및 요추 염좌 등 상해를 입었고 상대방은 경미한 사고라며 대인 보상을 거부하였습니다.","ruling":"가해차량 100% : 피해차량 0%","reason":"정차 중인 차량에는 과실이 없으며, 후방 차량의 전방주시 의무 위반 및 안전거리 미확보가 사고의 유일한 원인으로 판단되었습니다. 법원은 ''경미한 충격''이라는 주장만으로 상해 발생 가능성을 부정할 수 없다고 판시하였으며, 보험사의 직접 청구권 행사를 인정하였습니다."},{"title":"내리막길 정차 중 추돌 및 대인 보상 거부 분쟁 (금융감독원 분쟁조정)","facts":"내리막 경사로에서 신호 대기 중이던 차량을 후방 차량이 추돌, 가해 차주가 ''접촉이 경미하다''며 대인 접수를 거부하고 보험사에 대인 사고를 신고하지 않은 사례입니다.","ruling":"가해차량 100% : 피해차량 0%, 피해자 직접 청구 인용","reason":"금감원은 차주의 대인 접수 거부와 무관하게 피해자가 가해차량 보험사에 직접 청구할 권리가 있음을 확인하였고, 보험사는 피해자의 직접 청구를 정당한 이유 없이 거절할 수 없다고 결정하였습니다."}],"notes":["차주가 대인 접수를 거부하더라도 상법 제724조에 따라 피해자는 상대방 보험사에 직접 대인 청구가 가능합니다. 보험사 고객센터에 ''피해자 직접 청구'' 의사를 명시하여 접수하세요.","상대방 보험사 담당자가 현장에서 100:0을 인정한 내용은 녹취 또는 문자/카카오톡 등으로 반드시 증거를 보존하세요.","경미한 추돌이라도 신체 증상(목, 허리 통증 등)이 있다면 즉시 병원(정형외과·한의원)을 방문하여 진단서를 발급받으세요. 이후 증상 발현 시 인과관계 입증이 어려울 수 있습니다.","내리막길이라는 도로 조건과 중립 기어 상태에서의 정차는 상대방의 부주의를 더욱 명확히 입증하는 요소이므로, 블랙박스 영상 및 현장 사진을 보존하세요.","상대방 보험사가 대인 처리를 계속 거부할 경우 금융감독원(1332) 또는 금융분쟁조정위원회에 민원을 제기하거나, 교통사고 전담 변호사를 통한 법적 조치를 고려하세요.","본인 차량에 자동차보험 무보험차상해 또는 자기신체사고 특약이 있다면 우선 본인 보험으로 치료 후 상대방에게 구상 처리할 수도 있습니다."],"needed":["상대방 보험사 담당자의 100:0 인정 발언 녹취 또는 문자 증거 확보 여부","블랙박스 영상(본인 차량 후방 카메라 또는 상대방 전방 카메라) 저장 여부","현재 신체 증상(경추·요추 통증 등) 유무 및 병원 진단 여부","상대방 차량 보험사명 및 증권번호 (직접 청구 시 필요)","사고 발생 일시·장소 및 신고 여부 (경찰 사고 접수 여부)"]}'::jsonb, fault_ratio_a = 0, fault_ratio_b = 100, chart_code = '차41-1', summary = '내리막길 신호 정차 중 후방 차량이 조수석 물건을 집으려다 브레이크에서 발을 떼어 본인 차량 후미를 추돌한 사고입니다. 상대방 보험사 담당자도 현장에서 100:0을 인정하였으며, 이는 전형적인 후행 추돌 사고에 해당합니다. 상대방 차주가 대인 접수를 거부하고 있어 추가 조치가 필요한 상황입니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = '3c40f3d4-8580-462c-a3ab-11240a68c14e';
update posts set analysis = '{"summary":"2024년 1월, 상대 차량이 두 개 차선을 한 번에 변경하는 과정에서 직진 중이던 본인 차량과 충돌한 사고입니다. 목격자가 상대방 100% 과실임을 확인하였으며, 상대 차량은 책임보험만 가입된 렌트차량으로 확인되었습니다. 본인은 임신 8개월 상태로 사고를 당한 피해자입니다.","chartCode":"차42-2","chartName":"진로변경 중 충돌 (동일방향)","ratio":{"a":{"label":"본인 차량 (직진)","percent":0},"b":{"label":"상대 차량 (2차선 변경)","percent":100},"reason":"상대 차량이 두 개 차선을 한 번에 무리하게 변경하는 과정에서 직진 중이던 본인 차량을 충돌한 사안으로, 진로변경 차량의 안전의무 위반이 명백합니다. 목격자가 상대방 전적 과실임을 진술하였고, 상대 차주 본인도 현장에서 과실을 인정하였습니다. 본인 차량은 정상 직진 중이었으므로 특별한 과실 가산 요소가 없어 상대방 100% 과실로 판단됩니다."},"laws":[{"name":"도로교통법 제19조(안전거리 확보 등)","content":"모든 차의 운전자는 진로를 변경할 경우 변경하려는 방향의 차량 흐름을 방해하지 않도록 안전을 확인한 후 진로를 변경하여야 한다.","relevance":"상대 차량이 두 개 차선을 동시에 변경하면서 직진 차량의 통행을 방해한 행위에 직접 적용됩니다.","effect":"진로변경 의무 위반으로 상대 차량의 과실이 인정되며, 손해배상 책임이 가중됩니다."},{"name":"도로교통법 제38조(차의 신호)","content":"모든 차의 운전자는 진로를 바꾸려는 경우 손이나 방향지시기 또는 등화로써 그 행위가 끝날 때까지 신호를 하여야 한다.","relevance":"2차선 동시 변경 시 방향지시 의무를 충분히 이행했는지 여부가 과실 판단의 핵심 요소입니다.","effect":"방향지시 불이행 또는 불충분한 신호는 추가 과실 요소로 작용하여 상대방 과실 비율을 높입니다."},{"name":"민법 제750조(불법행위의 내용)","content":"고의 또는 과실로 인한 위법행위로 타인에게 손해를 가한 자는 그 손해를 배상할 책임이 있다.","relevance":"상대 차량의 과실 있는 진로변경으로 발생한 신체적·재산적 손해 전반에 대한 배상 청구의 근거가 됩니다.","effect":"임신 중 부상에 따른 치료비, 위자료, 태아에 대한 손해 배상 청구가 가능합니다."}],"cases":[{"title":"2차선 동시 변경 직진차 충돌 사건 (서울중앙지방법원)","facts":"피고 차량이 2개 차선을 연속으로 급변경하던 중 2차로를 직진하던 원고 차량의 측면을 충격한 사안","ruling":"피고(진로변경 차량) 100% : 원고(직진 차량) 0%","reason":"직진 차량은 정상 통행 중이었고 상대 차량의 갑작스러운 2차선 변경을 예측하거나 회피하기 어려웠으므로 피해 차량의 과실을 인정하지 않았습니다."},{"title":"렌트차량 책임보험 한도 초과 손해배상 사건","facts":"책임보험만 가입된 렌트 차량이 사고를 야기하여 피해자가 책임보험 한도를 초과하는 치료비 및 위자료를 청구한 사안","ruling":"렌트 차량 운전자 및 렌트 회사 연대 배상 책임 인정","reason":"책임보험 한도(대인 1인당 최대 1억 5천만 원) 초과분은 차량 소유자(렌트 회사) 및 운전자에게 직접 청구 가능하며, 임신 중 피해자에 대한 위자료는 일반 기준보다 높게 산정될 수 있습니다."}],"notes":["목격자 블랙박스 영상은 과실 입증의 핵심 증거이므로 반드시 조속히 확보하시기 바랍니다.","상대 차량이 책임보험만 가입된 경우, 책임보험 한도(대인 1인 최대 1억 5천만 원) 초과 치료비는 상대 운전자 또는 렌트 회사에 직접 청구해야 합니다.","임신 8개월 상태의 사고는 태아 건강에 대한 검사 및 치료도 손해배상 범위에 포함될 수 있으므로 산부인과 진료 기록을 반드시 보존하십시오.","본인 차량에 자동차보험(종합보험)이 있다면 자기신체사고(자손) 또는 무보험차상해 특약을 통해 우선 보상받고 상대방에게 구상하는 방법도 검토하십시오.","상대 차주가 현장에서 과실을 인정한 발언은 문자·녹음 등으로 보존해 두시면 향후 분쟁 시 유리합니다.","렌트 차량 사고의 경우 렌트 회사(차량 소유자)도 공동 불법행위자로서 배상 책임을 질 수 있습니다."],"needed":["목격자 블랙박스 영상 원본 확보 여부","본인 차량 블랙박스 영상 보존 여부","상대 렌트 차량의 렌트 회사명 및 종합보험 가입 여부 재확인","상대 운전자의 추가 임의보험(종합보험) 개인 가입 여부","사고 당시 경찰 신고 및 사고 사실 확인원 발급 여부","임신 관련 산부인과 진단서 및 태아 이상 여부 검사 기록","현재 치료 중인 상해 진단명 및 치료 기간 (향후 보상 산정에 필요)"]}'::jsonb, fault_ratio_a = 0, fault_ratio_b = 100, chart_code = '차42-2', summary = '2024년 1월, 상대 차량이 두 개 차선을 한 번에 변경하는 과정에서 직진 중이던 본인 차량과 충돌한 사고입니다. 목격자가 상대방 100% 과실임을 확인하였으며, 상대 차량은 책임보험만 가입된 렌트차량으로 확인되었습니다. 본인은 임신 8개월 상태로 사고를 당한 피해자입니다.', title = '급 진로변경 끼어들기 사고 (차42-2)' where id = 'bb503bae-439f-4c7e-9fd6-46caa1d5e846';
update posts set analysis = '{"summary":"비신호 교차로에서 본인 차량이 선진입한 상황에서 후진입한 상대방 레이 차량이 측면에서 추월하듯 진입하여 충돌한 사고입니다. 경찰 조사에서도 본인 차량의 선진입 사실이 확인되었으나, 분쟁심의위원회에서 본인 과실 20%가 산정된 상황입니다. 보험사를 통한 소송 절차로 과실비율 재산정을 진행 중입니다.","chartCode":"차11-1","chartName":"비신호 교차로 직진 차량 간 충돌 (선진입·후진입)","ratio":{"a":{"label":"본인 차량 (선진입 직진)","percent":20},"b":{"label":"상대 차량 (후진입 측면 진입)","percent":80},"reason":"비신호 교차로에서 선진입 차량은 통행 우선권을 가지며, 후진입 차량은 선진입 차량의 진행을 방해해서는 안 됩니다. 경찰 조사에서 선진입이 확인된 만큼 상대방의 기본 과실이 크게 인정되어야 하며, 도표 차11-1 기준 후진입 측면 충돌 시 후진입 차량이 80%, 선진입 차량이 20%의 과실이 적용됩니다. 단, 블랙박스·CCTV 영상 등으로 선진입 시점 차이가 명백히 입증될 경우 상대방 과실은 90~100%까지도 가능합니다."},"laws":[{"name":"도로교통법 제26조(교통정리가 없는 교차로에서의 양보운전)","content":"교통정리가 행하여지고 있지 아니하는 교차로에 들어가려는 차의 운전자는 이미 교차로에 들어가 있는 다른 차가 있을 때에는 그 차에 진로를 양보하여야 한다.","relevance":"본인 차량이 선진입한 상황에서 후진입한 상대방 레이 차량은 본인 차량에 진로를 양보할 의무가 있습니다.","effect":"후진입 차량인 상대방의 양보의무 위반이 인정되어 상대방의 과실 비율이 높아집니다."},{"name":"도로교통법 제13조의2(자동차 등의 통행방법 특례)","content":"차마의 운전자는 다른 차마의 정상적인 통행을 방해할 우려가 있는 경우에는 끼어들거나 앞지르지 아니하여야 한다.","relevance":"상대방 차량이 이미 진입 중인 본인 차량의 측면을 추월하듯 진입한 행위는 정상 통행 방해에 해당합니다.","effect":"상대방의 무리한 진입 및 추월 시도가 과실 가중 요인으로 작용합니다."},{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치·제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"비신호 교차로 진입 시 양측 모두 안전운전 의무를 부담하나, 후진입 차량인 상대방의 의무 위반 정도가 더 큽니다.","effect":"쌍방 안전운전 의무를 근거로 본인에게도 소폭의 과실(20%)이 부과될 수 있으나, 선진입 사실이 명확할수록 본인 과실은 감소합니다."}],"cases":[{"title":"비신호 교차로 선진입·후진입 측면 충돌 사건 (서울중앙지법)","facts":"비신호 교차로에서 A 차량이 먼저 진입하여 통과 중, 후진입한 B 차량이 측면에서 충돌한 사안. 블랙박스 영상으로 A의 선진입이 명확히 확인됨.","ruling":"A(선진입) 20% : B(후진입) 80%","reason":"선진입 차량에 대한 후진입 차량의 양보의무 위반(도로교통법 제26조)이 인정되었고, 선진입 시점이 영상으로 명확히 입증되어 후진입 차량의 과실이 80%로 결정됨. 선진입 차량도 교차로 진입 시 안전 확인 의무가 있어 20% 과실 부과."},{"title":"분쟁심의위원회 결정 불복 소송 (교통사고 과실비율 재산정)","facts":"분심위에서 선진입 차량에 20%의 과실을 부과한 결정에 대해 운전자가 불복, 블랙박스 영상 및 경찰 조사 결과를 증거로 소송 제기.","ruling":"법원에서 A(선진입) 10~20% : B(후진입) 80~90%로 조정","reason":"법원은 경찰 조사 결과와 블랙박스 영상을 종합하여 선진입 사실을 확인하고, 후진입 차량의 양보의무 위반을 주된 과실 원인으로 판단. 선진입 시점 차이가 클수록 피해자 과실은 더욱 감소."}],"notes":["분쟁심의위원회(분심위)의 결정은 법원 판결과 다를 수 있으며, 소송을 통해 과실비율 재산정이 가능합니다.","선진입 사실을 입증하는 블랙박스 영상, CCTV 영상, 경찰 조사 결과서는 소송에서 가장 핵심적인 증거입니다.","경찰 조사에서 선진입이 인정된 경우, 해당 조사 결과(교통사고 사실확인원, 조사 경위서 등)를 반드시 소송 증거로 제출하세요.","상대방 레이 차량이 측면에서 추월하듯 진입한 사실(진행 방향, 충돌 부위)이 명확히 확인될수록 본인 과실은 줄어들 수 있습니다.","도표 차11-1 기준 기본 과실비율은 선진입 20% : 후진입 80%이나, 선진입 시점 차이가 현저하거나 상대방의 과속·무리한 진입이 인정되면 수정 요소 적용으로 상대방 과실이 최대 90~100%까지 인정될 수 있습니다."],"needed":["블랙박스 또는 CCTV 영상 확보 여부 및 선진입 시점 차이(몇 초 선진입인지)","충돌 부위 사진 (본인 차량 및 상대 레이 차량의 파손 위치)","경찰 교통사고 사실확인원 및 조사 결과서 원본","상대방 레이 차량의 진입 속도 및 방향 (과속 여부)","교차로 구조 (동일 폭 도로인지, 넓고 좁은 도로 간 교차로인지)","분심위 결정 통보서 (결정 근거 및 이유 확인용)","보험사 소송 위임 계약서 및 진행 일정 확인"]}'::jsonb, fault_ratio_a = 20, fault_ratio_b = 80, chart_code = '차11-1', summary = '비신호 교차로에서 본인 차량이 선진입한 상황에서 후진입한 상대방 레이 차량이 측면에서 추월하듯 진입하여 충돌한 사고입니다. 경찰 조사에서도 본인 차량의 선진입 사실이 확인되었으나, 분쟁심의위원회에서 본인 과실 20%가 산정된 상황입니다. 보험사를 통한 소송 절차로 과실비율 재산정을 진행 중입니다.', title = '비신호 교차로 직진 vs 우회전 (차11-1)' where id = '436cc899-db94-4a9a-b886-b79537000460';
update posts set analysis = '{"summary":"입력된 사고 내용이 불충분하여 정확한 사고 분석이 어렵습니다. 구체적인 사고 상황, 도로 유형, 신호 여부, 차량 진행 방향 등의 정보가 필요합니다. 아래는 정보 부족으로 인한 임시 분석입니다.","chartCode":"차41-1","chartName":"동일방향 후행추돌(전방주시태만)","ratio":{"a":{"label":"본인 차량 (미상)","percent":50},"b":{"label":"상대 차량 (미상)","percent":50},"reason":"사고 상황에 대한 구체적인 정보가 제공되지 않아 과실비율을 정확히 산정할 수 없습니다. 사고 유형, 도로 상황, 신호 여부, 차량 행동 등 상세 정보를 입력해 주시면 정확한 분석이 가능합니다. 현재는 정보 부족으로 50:50으로 임시 표기합니다."},"laws":[{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치와 제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"사고 상황과 무관하게 모든 운전자에게 적용되는 기본 의무 조항입니다.","effect":"안전운전 의무 위반 시 과실 가중 사유로 적용됩니다."},{"name":"도로교통법 제1조(목적)","content":"이 법은 도로에서 일어나는 교통상의 모든 위험과 장해를 방지하고 제거하여 안전하고 원활한 교통을 확보함을 목적으로 한다.","relevance":"교통사고 분석의 기본 법적 근거입니다.","effect":"교통사고 관련 모든 법적 판단의 기초가 됩니다."}],"cases":[{"title":"정보 부족으로 유사 사례 제시 불가","facts":"사고 상황에 대한 구체적인 정보(도로 유형, 신호 여부, 차량 행동, 사고 경위 등)가 입력되지 않아 유사 판례를 제시하기 어렵습니다.","ruling":"미상","reason":"정확한 사고 유형이 파악되지 않아 판례 적용이 불가합니다."}],"notes":["입력하신 내용(''ㅈㄱㄴ'')으로는 사고 상황을 파악할 수 없습니다.","정확한 분석을 위해 아래 필요한 정보를 추가로 입력해 주세요.","과실비율 50:50은 임시 값으로 실제 사고와 다를 수 있습니다."],"needed":["사고 발생 도로 유형(교차로/직선도로/고속도로 등)","신호 여부(신호등 유무, 신호 색상)","본인 차량의 진행 방향 및 행동(직진/좌회전/우회전/정차 등)","상대 차량의 진행 방향 및 행동","사고 발생 경위(충돌 위치, 방향 등)","사고 당시 속도 및 도로 상황"]}'::jsonb, fault_ratio_a = 50, fault_ratio_b = 50, chart_code = '차41-1', summary = '입력된 사고 내용이 불충분하여 정확한 사고 분석이 어렵습니다. 구체적인 사고 상황, 도로 유형, 신호 여부, 차량 진행 방향 등의 정보가 필요합니다. 아래는 정보 부족으로 인한 임시 분석입니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = 'e284f8df-57eb-48ad-a191-4dea26fbdf51';
update posts set analysis = '{"summary":"1차선에서 직진 주행 중인 본인 차량(K3)과 2차선에서 정차 후 1차선으로 차선변경을 시도한 상대 차량(BMW 520i) 간의 접촉사고입니다. 상대 차량은 버스에 막혀 2차선 정차 중 1차선으로 진입을 시도하였고, 본인 차량은 앞차(렉스턴) 뒤를 따라 시속 30~35km로 직진 주행 중이었습니다. 차선변경 차량의 안전의무 위반이 주요 과실 요인입니다.","chartCode":"차42-2","chartName":"진로변경 중 접촉사고","ratio":{"a":{"label":"본인 차량 (직진)","percent":20},"b":{"label":"상대 차량 (차선변경)","percent":80},"reason":"차선변경을 시도한 상대 차량(BMW)은 후방 차량의 진행을 방해하지 않을 의무가 있으며, 안전 확인 없이 진입한 과실이 큽니다. 본인 차량은 직진 중이었으나 앞차(렉스턴) 후방에서 주행 중 상대 차량 움직임에 대한 전방주시 및 회피 가능성 여부가 일부 과실로 고려될 수 있습니다. 통상 진로변경 사고의 기본 과실비율은 변경 차량 70~80%, 직진 차량 20~30%로 적용됩니다."},"laws":[{"name":"도로교통법 제19조(안전거리 확보 등)","content":"모든 차의 운전자는 같은 방향으로 가고 있는 앞차의 뒤를 따르는 경우에는 앞차가 갑자기 정지하게 되는 경우 그 앞차와의 충돌을 피할 수 있는 필요한 거리를 확보하여야 한다.","relevance":"본인 차량의 앞차 추종 시 안전거리 확보 의무와 관련됩니다.","effect":"안전거리 미확보 시 본인 차량의 과실이 가산될 수 있습니다."},{"name":"도로교통법 제19조 제3항(진로변경 금지)","content":"차의 운전자는 차의 진로를 변경하려는 경우에 그 변경하려는 방향으로 오고 있는 다른 차의 정상적인 통행에 장애를 줄 우려가 있을 때에는 진로를 변경하여서는 아니 된다.","relevance":"상대 차량이 직진 중인 본인 차량의 통행을 방해하며 차선변경을 시도한 행위에 직접 적용됩니다.","effect":"상대 차량의 진로변경 의무 위반으로 주요 과실 원인이 됩니다."},{"name":"도로교통법 제38조(차의 신호)","content":"모든 차의 운전자는 좌회전·우회전·횡단·유턴·서행·정지 또는 후진을 하거나 같은 방향으로 진행하면서 진로를 바꾸려고 하는 경우에는 손이나 방향지시기 또는 등화로써 그 행위가 끝날 때까지 신호를 하여야 한다.","relevance":"상대 차량의 방향지시등 점등 여부 및 신호 시점이 과실 판단에 영향을 미칩니다.","effect":"방향지시등 미점등 또는 뒤늦은 점등 시 상대 차량 과실이 추가 가산됩니다."}],"cases":[{"title":"진로변경 차량과 직진 차량 간 접촉사고 (서울중앙지방법원)","facts":"2차선 주행 차량이 방향지시등을 켜지 않거나 뒤늦게 켠 상태에서 1차선으로 차선변경 중 직진 주행 중인 차량과 접촉한 사고","ruling":"차선변경 차량 70~80% : 직진 차량 20~30%","reason":"차선변경 차량은 후방 및 측방 안전 확인 후 진입해야 할 의무가 있으며, 직진 차량은 전방주시 의무 및 회피 가능 여부에 따라 일부 과실이 인정됨"},{"title":"정차 후 차선변경 중 직진 차량과 접촉사고","facts":"버스 등 전방 장애물로 인해 정차 중이던 차량이 인접 차선으로 변경 시도 중 해당 차선 직진 차량과 충돌","ruling":"차선변경 차량 80% : 직진 차량 20%","reason":"정차 상태에서 차선변경을 개시한 경우 후방 차량의 속도와 거리를 충분히 확인하지 않은 과실이 크고, 직진 차량은 정상 주행 중이므로 과실이 상대적으로 낮게 인정됨"}],"notes":["블랙박스 영상이 있다면 상대 차량의 방향지시등 점등 여부, 진입 시점, 본인 차량의 속도 등을 확인하는 것이 중요합니다.","상대 차량이 방향지시등을 미점등하였거나 갑작스럽게 진입한 경우 상대 과실이 최대 90%까지 인정될 수 있습니다.","본인 차량 속도(30~35km/h)는 비교적 저속이므로 회피 불가능 상황으로 인정될 가능성이 있습니다.","차량 파손 부위(본인 차량 좌측 앞 범퍼, 상대 차량 우측 후미 등)를 사진으로 확보해 두시기 바랍니다."],"needed":["블랙박스 영상 유무 및 영상 내 상대 차량 방향지시등 점등 여부","접촉 당시 본인 차량과 상대 차량의 정확한 위치 및 파손 부위","상대 차량 운전자의 진술(방향지시등 점등 주장 여부)","사고 발생 도로의 차선 구조 및 주변 CCTV 존재 여부"]}'::jsonb, fault_ratio_a = 20, fault_ratio_b = 80, chart_code = '차42-2', summary = '1차선에서 직진 주행 중인 본인 차량(K3)과 2차선에서 정차 후 1차선으로 차선변경을 시도한 상대 차량(BMW 520i) 간의 접촉사고입니다. 상대 차량은 버스에 막혀 2차선 정차 중 1차선으로 진입을 시도하였고, 본인 차량은 앞차(렉스턴) 뒤를 따라 시속 30~35km로 직진 주행 중이었습니다. 차선변경 차량의 안전의무 위반이 주요 과실 요인입니다.', title = '급 진로변경 끼어들기 사고 (차42-2)' where id = 'caea5ae5-ce18-425d-8853-27b64c6e4b9e';
update posts set analysis = '{"summary":"천안삼거리 교차로에서 본인 차량이 좌회전을 시도하던 중 사고가 발생하였습니다. 좌회전 차량은 교차로 진입 전 반드시 대향 직진 차량 및 보행자를 확인하고 안전하게 통행할 의무가 있습니다. 구체적인 신호 상태 및 상대방 차량의 행동에 따라 과실비율이 달라질 수 있습니다.","chartCode":"차11-1","chartName":"비신호교차로 좌회전 대 직진","ratio":{"a":{"label":"본인 차량 (좌회전)","percent":70},"b":{"label":"상대 차량 (직진 또는 기타)","percent":30},"reason":"좌회전 차량은 교차로에서 반대편 직진 차량 및 횡단 차량에 대한 양보 의무가 있어 기본 과실이 높게 산정됩니다. 다만, 상대방 차량의 속도위반, 신호 준수 여부 등에 따라 과실이 조정될 수 있습니다. 사고 당시 신호 상태 및 쌍방 행동에 대한 추가 정보가 확인되면 비율은 변동될 수 있습니다."},"laws":[{"name":"도로교통법 제25조(교차로 통행방법)","content":"교차로에서 좌회전하려는 차마의 운전자는 미리 도로의 중앙선을 따라 교차로 중심 안쪽을 이용하여 좌회전하여야 하며, 다른 차량의 통행을 방해하지 않아야 한다.","relevance":"좌회전 차량의 통행 방법 및 안전 의무에 직접 적용","effect":"좌회전 차량의 기본 과실 인정 근거"},{"name":"도로교통법 제26조(교통정리가 없는 교차로에서의 양보운전)","content":"교통정리가 없는 교차로에서는 넓은 도로 또는 먼저 진입한 차량에 양보하여야 하며, 좌회전 차량은 직진 또는 우회전 차량에 양보할 의무가 있다.","relevance":"비신호 또는 신호 상태 불명확 상황에서의 좌회전 양보 의무","effect":"좌회전 차량의 과실 가중 근거"},{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치·제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"쌍방 운전자의 안전운전 의무 위반 여부 판단 기준","effect":"과실 산정 시 안전운전 의무 위반 가중 또는 감경 근거"}],"cases":[{"title":"교차로 좌회전 중 직진 차량과의 충돌 사고","facts":"피고(좌회전 차량)가 교차로에서 좌회전을 시도하던 중 직진 진행 중이던 원고 차량과 충돌한 사안","ruling":"좌회전 차량 70 : 직진 차량 30","reason":"좌회전 차량은 교차로에서 직진 차량에 대한 양보 의무가 있으며, 진행 방향을 변경할 때 충분한 안전 확인을 하지 않은 과실이 인정됨. 직진 차량도 제한속도 준수 및 전방주시 의무가 있어 일부 과실 인정."},{"title":"신호교차로 좌회전 비보호 시 직진 차량과의 충돌","facts":"비보호 좌회전 구간에서 좌회전을 시도하던 차량이 맞은편 직진 차량을 발견하지 못하고 충돌한 사안","ruling":"좌회전 차량 80 : 직진 차량 20","reason":"비보호 좌회전은 반드시 대향 직진 차량에 양보하여야 하며, 이를 위반한 좌회전 차량의 과실이 주로 인정됨. 직진 차량의 과속 또는 전방주시 태만이 확인될 경우 과실 일부 인정."}],"notes":["본 분석은 제공된 정보를 바탕으로 한 예측치이며, 실제 보험사 또는 법원의 판단과 다를 수 있습니다.","신호 유형(보호좌회전, 비보호좌회전, 비신호)에 따라 과실비율이 크게 달라집니다.","CCTV, 블랙박스 영상 등 객관적 증거가 확보되면 과실 판단에 결정적 영향을 미칩니다.","천안삼거리 교차로의 신호 체계 및 도로 구조에 따라 추가 조정이 필요합니다."],"needed":["사고 당시 신호등 상태 (보호좌회전 신호인지, 비보호인지, 신호 없음인지)","상대방 차량의 진행 방향 및 행동 (직진, 우회전, 역주행 등)","사고 발생 지점의 정확한 위치 (교차로 내부인지, 진출입로인지)","블랙박스 또는 CCTV 영상 확보 여부","쌍방 차량의 속도 및 충돌 부위","목격자 진술 또는 경찰 조사 결과"]}'::jsonb, fault_ratio_a = 70, fault_ratio_b = 30, chart_code = '차11-1', summary = '천안삼거리 교차로에서 본인 차량이 좌회전을 시도하던 중 사고가 발생하였습니다. 좌회전 차량은 교차로 진입 전 반드시 대향 직진 차량 및 보행자를 확인하고 안전하게 통행할 의무가 있습니다. 구체적인 신호 상태 및 상대방 차량의 행동에 따라 과실비율이 달라질 수 있습니다.', title = '비신호 교차로 직진 vs 우회전 (차11-1)' where id = '5bbd0ecf-dd48-477a-88de-5b32ac7190c4';
update posts set analysis = '{"summary":"제공된 정보만으로는 구체적인 사고 상황(사고 유형, 도로 환경, 신호 여부, 당사자 행동 등)을 파악할 수 없습니다. ''보배드림에 블박 100''이라는 언급만으로는 정확한 과실비율 분석이 불가능합니다. 아래 필요한 정보를 추가로 입력해 주시면 정확한 분석이 가능합니다.","chartCode":"차41-1","chartName":"동일방향 후행추돌(전방주시태만)","ratio":{"a":{"label":"본인 차량 (미상)","percent":50},"b":{"label":"상대 차량 (미상)","percent":50},"reason":"사고 유형, 도로 환경, 신호 여부, 속도, 당사자 행동 등 구체적인 정보가 전혀 제공되지 않아 과실비율을 산정할 수 없습니다. ''블박 100''이라는 표현은 블랙박스 영상 기준 특정 차량의 과실이 100%라는 의미일 수 있으나, 해당 사고의 유형과 상황을 모르면 확인이 불가합니다. 정확한 분석을 위해 아래 필요한 정보를 입력해 주세요."},"laws":[{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치·제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조·성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"사고 유형에 관계없이 안전운전 의무 위반 여부는 과실 판단의 기본 근거가 됩니다.","effect":"위반 시 과실비율 상향 요인으로 작용"},{"name":"도로교통법 제19조(안전거리 확보)","content":"모든 차의 운전자는 같은 방향으로 가고 있는 앞차의 뒤를 따르는 경우에는 앞차가 갑자기 정지하게 되는 경우 그 앞차와의 충돌을 피할 수 있는 필요한 거리를 확보하여야 한다.","relevance":"추돌 사고의 경우 안전거리 미확보가 핵심 과실 근거가 됩니다.","effect":"안전거리 미확보 시 후행 차량 과실 100% 또는 상향"}],"cases":[{"title":"정보 부족으로 유사 사례 제시 불가","facts":"사고 유형이 특정되지 않아 적합한 판례를 선택할 수 없습니다.","ruling":"미정","reason":"사고 상황(교차로/직진/후진/추돌 등)과 당사자 행동이 명확해야 관련 판례 적용이 가능합니다."}],"notes":["''블박 100''은 블랙박스 영상 분석 결과 특정 당사자의 과실이 100%라는 의미로 통용되나, 법적 과실비율은 영상만으로 결정되지 않습니다.","보배드림 등 커뮤니티 의견은 참고용이며 법적 효력이 없습니다.","정확한 분석을 위해 아래 항목을 입력해 주세요."],"needed":["사고 발생 장소(교차로/직선도로/주차장 등)","신호 유무(신호교차로/비신호교차로)","본인 차량의 행동(직진/좌회전/우회전/정차 등)","상대 차량의 행동(직진/후진/신호위반 등)","충돌 방향(정면/측면/후방)","사고 당시 속도 및 도로 상황","블랙박스 영상 내용 요약"]}'::jsonb, fault_ratio_a = 50, fault_ratio_b = 50, chart_code = '차41-1', summary = '제공된 정보만으로는 구체적인 사고 상황(사고 유형, 도로 환경, 신호 여부, 당사자 행동 등)을 파악할 수 없습니다. ''보배드림에 블박 100''이라는 언급만으로는 정확한 과실비율 분석이 불가능합니다. 아래 필요한 정보를 추가로 입력해 주시면 정확한 분석이 가능합니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = '8597c9cb-74bd-4539-983f-dc15e01201cc';
update posts set analysis = '{"summary":"회전교차로에서 발생한 사고로, 상대방 차량(노란색)이 방향지시등 없이 회전교차로에 진입하거나 회전 중 충돌한 사건입니다. 본인 차량(빨간색)은 회전교차로 내에서 정상 주행 중이었으나 상대방의 갑작스러운 진입으로 피해를 입었습니다. 방향지시등 미사용 및 양보 의무 위반이 핵심 쟁점입니다.","chartCode":"차10-1","chartName":"비신호 교차로 직진 vs 진입 충돌","ratio":{"a":{"label":"본인 차량 (회전 중)","percent":20},"b":{"label":"상대 차량 (진입/방향지시등 미사용)","percent":80},"reason":"회전교차로에서는 진입 차량이 회전 중인 차량에 양보할 의무가 있으며, 상대방이 방향지시등을 사용하지 않고 진입한 것은 중대한 과실입니다. 본인 차량은 회전교차로 내 정상 주행 중이었으므로 기본 과실은 낮으나, 방어운전 미흡 등 소폭의 과실이 인정될 수 있습니다."},"laws":[{"name":"도로교통법 제25조의2(회전교차로 통행방법)","content":"회전교차로에 진입하려는 차량은 회전교차로 내에서 주행 중인 차량에 양보하여야 하며, 진입 전 서행 또는 일시정지 의무가 있습니다.","relevance":"상대방 차량이 회전교차로 진입 시 회전 중인 본인 차량에 양보 의무를 위반한 핵심 근거입니다.","effect":"양보 의무 위반 차량에 과실 가중 적용"},{"name":"도로교통법 제38조(차의 신호)","content":"차의 운전자는 좌회전·우회전·횡단·유턴·서행·정지 또는 후진할 때 방향지시기를 조작하여 신호를 하여야 합니다.","relevance":"상대방이 회전교차로 진입 시 방향지시등을 사용하지 않은 것은 본 조항 위반으로, 과실 가중 사유가 됩니다.","effect":"방향지시등 미사용에 따른 과실 가중 (약 10~20% 추가)"},{"name":"도로교통법 제49조(모든 운전자의 준수사항)","content":"모든 운전자는 도로에서 타인에게 위험과 장해를 주는 방법으로 운전하여서는 아니 되며, 안전 운전 의무를 준수해야 합니다.","relevance":"상대방이 무신호·무양보로 진입하여 충돌을 야기한 행위는 안전운전 의무 위반에 해당합니다.","effect":"상대방 과실 인정의 추가 법적 근거"}],"cases":[{"title":"회전교차로 진입 차량과 회전 차량 간 충돌 사건","facts":"회전교차로 내에서 정상 주행 중인 차량과 방향지시등 없이 진입한 차량이 충돌한 사안으로, 진입 차량이 양보 의무를 이행하지 않음.","ruling":"진입 차량 70~80% : 회전 차량 20~30%","reason":"회전교차로 내 회전 차량의 우선권이 인정되며, 진입 차량의 양보 의무 위반 및 방향지시등 미사용이 주요 과실로 판단됨."},{"title":"교차로 진입 차량 신호 미사용 및 우선권 위반 사건","facts":"교차로 진입 차량이 방향지시등 없이 급진입하여 통행 우선권을 가진 차량과 충돌한 사안.","ruling":"진입 차량 75% : 우선 차량 25%","reason":"통행 우선권 위반 및 신호 미사용은 중대한 과실로 인정되며, 우선 차량도 방어운전 의무 일부 부담."}],"notes":["회전교차로는 진입 차량이 반드시 회전 중인 차량에 양보해야 하므로, 원칙적으로 상대방 과실이 큽니다.","방향지시등 미사용은 과실 가중 요소로 명확히 인정됩니다.","블랙박스 전방·후방 영상 확보가 과실 입증에 매우 중요하며, 후방 영상도 반드시 제출하시기 바랍니다.","사고 현장 사진, 차량 파손 부위 사진, 목격자 진술 등도 추가로 확보하시면 유리합니다.","회전교차로 노면 표시(진입 양보선, 화살표 등) 사진도 증거로 활용 가능합니다."],"needed":["블랙박스 후방 영상 (상대방 진입 경로 및 방향지시등 미사용 확인)","사고 발생 위치 (회전교차로 내 정확한 충돌 지점)","상대방 차량의 진입 방향 및 본인 차량의 회전 방향","차량 파손 부위 및 정도 (충돌 각도 파악)","목격자 진술 또는 CCTV 영상","상대방의 과실 인정 여부 및 보험사 접수 여부"]}'::jsonb, fault_ratio_a = 20, fault_ratio_b = 80, chart_code = '차10-1', summary = '회전교차로에서 발생한 사고로, 상대방 차량(노란색)이 방향지시등 없이 회전교차로에 진입하거나 회전 중 충돌한 사건입니다. 본인 차량(빨간색)은 회전교차로 내에서 정상 주행 중이었으나 상대방의 갑작스러운 진입으로 피해를 입었습니다. 방향지시등 미사용 및 양보 의무 위반이 핵심 쟁점입니다.', title = '비신호 교차로 직진 충돌 (차10-1)' where id = 'ff4f1b62-1cb0-48df-93ce-5fd7ba2e2c40';
update posts set analysis = '{"summary":"신호교차로에서 직진 신호에 따라 2차로로 직진 중이던 본인 차량에 1차로를 주행하던 상대 차량이 차선을 침범하여 접촉사고가 발생하였습니다. 상대방이 차선을 침범하여 발생한 사고로, 본인 차량의 과실은 매우 낮거나 없습니다. 상대방의 5대5 주장은 근거가 없으며, 블랙박스 영상이 결정적 증거가 됩니다.","chartCode":"차3-1","chartName":"신호교차로 직진 차량 간 충돌(차선 침범)","ratio":{"a":{"label":"본인 차량 (직진·2차로)","percent":10},"b":{"label":"상대 차량 (차선침범·1차로)","percent":90},"reason":"상대 차량이 1차로에서 2차로로 차선을 침범하여 발생한 사고이므로 상대방의 과실이 압도적으로 큽니다. 본인 차량은 지정 차로를 정상 직진하였으므로 기본 과실은 0에 가깝지만, 실무적으로 측방 주시 소홀 등 최소 과실 10%가 적용될 수 있습니다. 상대방의 5대5 주장은 사고 경위상 전혀 근거가 없습니다."},"laws":[{"name":"도로교통법 제14조(차로의 설치)","content":"차마의 운전자는 차로가 설치된 도로에서는 그 차로를 따라 통행하여야 하며, 지정된 차로를 벗어나서는 아니 됩니다.","relevance":"상대 차량이 1차로에서 2차로로 침범한 행위는 본 조항의 직접적 위반입니다.","effect":"차선 침범 차량에게 주된 과실이 귀속되며, 손해배상 책임이 집중됩니다."},{"name":"도로교통법 제19조(안전거리 확보 등)","content":"모든 차의 운전자는 같은 방향으로 가고 있는 앞차의 뒤를 따르는 때에는 앞차가 갑자기 정지하게 되는 경우 그 앞차와의 충돌을 피할 수 있는 필요한 거리를 확보하여야 하며, 옆 차로 차량과의 안전거리도 유지하여야 합니다.","relevance":"상대 차량이 옆 차로와의 안전거리를 유지하지 않고 침범한 점에서 관련됩니다.","effect":"안전거리 미확보 및 차선 침범으로 인한 과실 가중 요소가 됩니다."},{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치, 제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 됩니다.","relevance":"상대 차량이 차선을 침범하여 본인 차량에 위험을 초래한 것은 안전운전 의무 위반입니다.","effect":"안전운전 의무 위반으로 상대방의 손해배상 책임이 강화됩니다."}],"cases":[{"title":"신호교차로 직진 중 옆 차량 차선 침범 접촉사고","facts":"쌍방 모두 직진 신호에 교차로를 통과하던 중, 1차로 차량이 2차로로 차선을 침범하여 2차로 직진 차량과 접촉사고가 발생한 사례.","ruling":"차선 침범 차량 90% : 피해 차량 10%","reason":"차선을 침범한 차량에게 주과실이 인정되고, 피해 차량에게는 측방 주시 의무 소홀 등 최소 과실만 인정하는 것이 판례의 일반적 경향입니다. 블랙박스 등 영상 증거가 있으면 피해 차량 과실이 0%로 인정되는 사례도 있습니다."},{"title":"동일 방향 주행 중 차선 침범 사고 (보험개발원 기준)","facts":"편도 2차로 이상 도로에서 한쪽 차량이 차선을 침범하여 옆 차로 정상 주행 차량과 충돌한 사례.","ruling":"차선 침범 차량 80~90% : 상대 차량 10~20%","reason":"보험개발원 과실비율 인정기준상 차선 침범 차량에게 80~90%의 과실이 인정되며, 교차로 내 차선 침범의 경우 가중 적용될 수 있습니다."}],"notes":["블랙박스 영상(전방·측방)이 있다면 반드시 보험사에 즉시 제출하세요. 영상이 명확할수록 본인 과실이 0%로 인정될 가능성이 높아집니다.","같은 보험사(KB)라도 담당 직원이 분리 배정되어야 이해충돌이 없으므로, 본인 측 담당자가 별도로 지정되었는지 확인하세요.","상대방의 5대5 주장은 법적·판례상 근거가 없으므로, 블랙박스 영상 제출 후 보험사에 재산정을 요청하시기 바랍니다.","접촉 부위(본인 차량의 우측면, 상대 차량의 좌측면)도 차선 침범 방향을 입증하는 물리적 증거가 됩니다.","합의에 서명하기 전 과실비율이 확정될 때까지 서명을 보류하시고, 이의가 있으면 금융감독원 분쟁조정을 신청할 수 있습니다."],"needed":["블랙박스 영상 유무 및 촬영 각도(측방 촬영 여부)","접촉 부위 사진(본인 차량 및 상대 차량)","사고 당시 차선 구분(실선/점선 여부)","상대 차량이 차선 변경을 시도한 것인지, 단순 차선 이탈인지 여부","목격자 또는 CCTV 영상 존재 여부"]}'::jsonb, fault_ratio_a = 10, fault_ratio_b = 90, chart_code = '차3-1', summary = '신호교차로에서 직진 신호에 따라 2차로로 직진 중이던 본인 차량에 1차로를 주행하던 상대 차량이 차선을 침범하여 접촉사고가 발생하였습니다. 상대방이 차선을 침범하여 발생한 사고로, 본인 차량의 과실은 매우 낮거나 없습니다. 상대방의 5대5 주장은 근거가 없으며, 블랙박스 영상이 결정적 증거가 됩니다.', title = '좌회전 신호 중 신호위반 직진 충돌 (차3-1)' where id = '08d0229e-56c8-4698-80a4-49811b1fa3a7';
update posts set analysis = '{"summary":"본인 차량이 도로를 주행 중 상대방 차량의 급작스러운 행동(급제동, 끼어들기, 차선변경 등)으로 인해 추돌 또는 충격이 발생한 사고로 추정됩니다. 분심위에서 9:1(상대방:본인) 과실 결정이 내려진 사례입니다. 정확한 사고 유형 특정을 위해 추가 정보가 필요합니다.","chartCode":"차41-1","chartName":"동일방향 주행 중 후행차 추돌(전방주시태만)","ratio":{"a":{"label":"본인 차량 (후행 주행)","percent":10},"b":{"label":"상대 차량 (선행 급제동/차선변경)","percent":90},"reason":"분심위 결정 9:1 기준으로, 상대방 차량의 급제동 또는 갑작스러운 차선변경이 주된 과실입니다. 본인 차량에게 10%의 과실이 인정된 이유는 안전거리 미확보 또는 전방주시 소홀 가능성 때문입니다. 60~65km/h 속도에서 안전거리를 충분히 유지했는지 여부가 과실 판단의 핵심입니다."},"laws":[{"name":"도로교통법 제19조(안전거리 확보 등)","content":"모든 차의 운전자는 같은 방향으로 가고 있는 앞차의 뒤를 따르는 경우에는 앞차가 갑자기 정지하게 되는 경우 그 앞차와의 충돌을 피할 수 있는 필요한 거리를 확보하여야 한다.","relevance":"본인 차량의 안전거리 확보 의무와 관련되며, 이것이 10% 과실 산정의 근거가 됩니다.","effect":"안전거리 미확보 시 후행 차량에게 일부 과실 부과"},{"name":"도로교통법 제48조(안전운전 의무)","content":"모든 차의 운전자는 차의 조향장치와 제동장치, 그 밖의 장치를 정확하게 조작하여야 하며, 도로의 교통상황과 차의 구조 및 성능에 따라 다른 사람에게 위험과 장해를 주는 속도나 방법으로 운전하여서는 아니 된다.","relevance":"상대방 차량의 급제동 또는 위험한 차선변경이 안전운전 의무 위반에 해당합니다.","effect":"상대방의 주과실(90%) 근거 조항"},{"name":"도로교통법 제23조(끼어들기의 금지)","content":"모든 차의 운전자는 법령의 규정 또는 경찰공무원의 지시에 따르거나 위험방지를 위하여 정지 또는 서행하고 있는 다른 차의 앞에 끼어들지 못한다.","relevance":"상대방이 급작스러운 끼어들기 또는 차선변경을 한 경우 적용됩니다.","effect":"상대방 차량의 위반행위로 과실 가중"}],"cases":[{"title":"동일방향 주행 중 선행차 급제동으로 인한 후방 추돌 사고","facts":"피해차량이 일반도로에서 60km/h로 주행 중 전방 차량이 갑작스럽게 급제동하여 추돌한 사례. 블랙박스 영상으로 급제동 및 불필요한 차선변경이 확인됨.","ruling":"선행차(가해) 90% : 후행차(피해) 10%","reason":"선행차의 불필요한 급제동이 주과실이나, 후행차의 안전거리 미확보 과실을 10% 인정. 분심위 결정과 동일한 패턴의 판례."},{"title":"급차선변경 후 급제동으로 인한 추돌 사고","facts":"상대방 차량이 갑자기 차선을 변경한 직후 급제동하여 뒤따르던 본인 차량이 추돌한 사고. 본인 차량 속도 60~65km/h 수준.","ruling":"가해차량(차선변경+급제동) 85~90% : 피해차량 10~15%","reason":"차선변경 직후 급제동은 후방 차량이 회피하기 매우 어려운 상황을 만들므로 주과실은 선행차에 귀속. 다만 후행차의 속도 및 안전거리 관리 여부에 따라 일부 과실 인정."}],"notes":["분심위(분쟁심의위원회) 결정 9:1은 법원 판결과 다를 수 있으며, 소송 시 비율이 변동될 수 있습니다.","60~65km/h 속도 자체는 제한속도 이내라면 과실 가중 사유가 되지 않습니다.","블랙박스 영상에서 상대방의 급제동·급차선변경 등 위험행위가 명확히 확인될수록 본인 과실(10%)도 다툼이 가능합니다.","9:1 과실에서 본인 1의 과실은 주로 안전거리 미확보 또는 전방주시 소홀로 산정되는 경우가 많습니다.","상대방의 고의적 급제동(보험사기 의심)이라면 형사 고소 및 보험사기 신고도 고려하시기 바랍니다."],"needed":["정확한 사고 유형: 추돌인지, 측면충돌인지, 차선변경 중 충돌인지 구체적 상황","상대방 차량의 행동: 급제동, 끼어들기, 차선변경, 갑작스러운 정차 여부","사고 발생 도로 유형: 일반도로, 고속도로, 자동차전용도로 여부","블랙박스 영상 내용: 상대방 차량의 위반행위 영상 확보 여부","상대방의 신호위반, 중앙선 침범 등 명백한 법규위반 여부","본인 차량의 제동 흔적 및 충돌 직전 회피 시도 여부"]}'::jsonb, fault_ratio_a = 10, fault_ratio_b = 90, chart_code = '차41-1', summary = '본인 차량이 도로를 주행 중 상대방 차량의 급작스러운 행동(급제동, 끼어들기, 차선변경 등)으로 인해 추돌 또는 충격이 발생한 사고로 추정됩니다. 분심위에서 9:1(상대방:본인) 과실 결정이 내려진 사례입니다. 정확한 사고 유형 특정을 위해 추가 정보가 필요합니다.', title = '전방주시 태만 후행 추돌 (차41-1)' where id = 'b9079f54-5e03-48d4-b34a-e799e23a9571';
update posts set analysis = '{"summary":"본인(좌회전 차량)이 교차로에서 좌회전 중 직진하던 상대방 차량과 충돌한 사고입니다. 좌회전 차량은 직진 차량에 대한 양보 의무가 있으므로 기본적으로 좌회전 차량의 과실이 더 큽니다. 상대방이 주장하는 9:1 과실비율은 일반적인 기준보다 높은 편으로, 구체적인 사고 정황에 따라 조정이 가능합니다.","chartCode":"차13-1","chartName":"비신호교차로 좌회전 차 대 직진 차 충돌","ratio":{"a":{"label":"본인 차량 (좌회전)","percent":70},"b":{"label":"상대 차량 (직진)","percent":30},"reason":"비신호 교차로에서 좌회전 차량은 직진 차량에 대한 양보 의무를 부담하므로 기본 과실은 좌회전 차량 70%, 직진 차량 30%입니다. 다만 상대방이 주장하는 9:1(90:10)은 통상적인 기준을 크게 벗어나며, 신호교차로 여부·도로 폭·속도위반·진입 선후관계 등 구체적 사정에 따라 과실 비율이 달라질 수 있습니다."},"laws":[{"name":"도로교통법 제26조(교통정리가 없는 교차로에서의 양보운전)","content":"교통정리가 행하여지고 있지 아니하는 교차로에 들어가려는 차의 운전자는 이미 교차로에 들어가 있는 차가 있을 때에는 그 차에 진로를 양보하여야 하며, 직진 또는 우회전하려는 차에 진로를 양보하여야 한다.","relevance":"좌회전 차량은 직진 차량에 대해 명시적인 양보 의무를 부담하므로, 이를 위반한 경우 과실이 가중됩니다.","effect":"좌회전 차량의 기본 과실 가중 근거로 작용하며, 위반 시 과실비율이 상향 조정됩니다."},{"name":"도로교통법 제25조(교차로 통행방법)","content":"모든 차의 운전자는 교차로에서 좌회전을 하려는 경우에는 미리 도로의 중앙선을 따라 서행하면서 교차로의 중심 안쪽을 이용하여 좌회전하여야 한다.","relevance":"좌회전 시 서행 의무를 규정하며, 이를 준수했는지 여부가 과실 판단의 핵심 요소가 됩니다.","effect":"서행 의무 위반이 인정되면 좌회전 차량의 과실이 추가로 가중될 수 있습니다."},{"name":"도로교통법 제19조(안전거리 확보 등)","content":"모든 차의 운전자는 같은 방향으로 가고 있는 앞차의 뒤를 따르는 경우에는 앞차가 갑자기 정지하게 되는 경우 그 앞차와의 충돌을 피할 수 있는 필요한 안전거리를 확보하여야 한다.","relevance":"직진 차량도 전방 주시 의무 및 안전 운전 의무를 부담하며, 과속이나 전방 주시 태만이 있을 경우 직진 차량의 과실이 가중됩니다.","effect":"직진 차량의 과속·전방 주시 태만 입증 시 상대방 과실 비율이 상향 조정될 수 있습니다."}],"cases":[{"title":"비신호 교차로 좌회전 대 직진 충돌 사건","facts":"비신호 교차로에서 좌회전하던 차량과 직진하던 차량이 충돌한 사안으로, 좌회전 차량이 직진 차량의 진행을 방해한 경우.","ruling":"좌회전 차량 70% : 직진 차량 30%","reason":"직진 차량은 교차로 통행 우선권을 가지므로 좌회전 차량의 기본 과실을 높게 인정하되, 직진 차량도 전방 주시 의무 및 감속 의무를 부담하므로 30%의 과실을 인정하였습니다."},{"title":"신호교차로 좌회전 신호 위반 대 직진 충돌 사건","facts":"신호교차로에서 좌회전 보호신호 없이 좌회전을 시도하다 직진 신호에 진행하던 차량과 충돌한 사안.","ruling":"좌회전 차량 80~90% : 직진 차량 10~20%","reason":"신호교차로에서 직진 신호를 무시하고 좌회전한 경우 좌회전 차량의 과실이 대폭 가중되며, 직진 차량에도 방어 운전 의무 위반 등이 인정되면 일부 과실이 부과됩니다."}],"notes":["신호교차로인지 비신호교차로인지에 따라 적용 도표 및 기본 과실비율이 달라집니다.","좌회전 보호신호가 있는 교차로에서 보호신호에 따라 좌회전한 경우 과실이 대폭 감소할 수 있습니다.","상대방 직진 차량의 과속, 신호위반, 전방 주시 태만 등이 입증되면 본인 과실이 낮아질 수 있습니다.","블랙박스 영상, 목격자 진술, 사고 현장 스키드마크 등 객관적 증거 확보가 중요합니다.","분쟁심의위원회(분심위)에서는 세부 사실관계를 종합적으로 검토하여 과실비율을 조정하므로, 유리한 증거를 최대한 준비하시기 바랍니다.","상대방 주장 9:1은 일반적인 기준(약 7:3)과 차이가 있으므로, 분심위에서 조정될 가능성이 높습니다."],"needed":["해당 교차로가 신호교차로인지 비신호교차로인지 여부","신호교차로라면 좌회전 보호신호 유무 및 당시 신호 상태","본인 및 상대방 차량의 주행 속도(블랙박스 영상, GPS 데이터 등)","충돌 지점(교차로 내 위치) 및 충돌 부위","블랙박스 영상(전·후방) 확보 여부","도로 폭 및 일방통행 여부","사고 당시 기상 및 도로 상태","상대방 차량의 과속 또는 신호위반 여부에 대한 증거"]}'::jsonb, fault_ratio_a = 70, fault_ratio_b = 30, chart_code = '차13-1', summary = '본인(좌회전 차량)이 교차로에서 좌회전 중 직진하던 상대방 차량과 충돌한 사고입니다. 좌회전 차량은 직진 차량에 대한 양보 의무가 있으므로 기본적으로 좌회전 차량의 과실이 더 큽니다. 상대방이 주장하는 9:1 과실비율은 일반적인 기준보다 높은 편으로, 구체적인 사고 정황에 따라 조정이 가능합니다.', title = '비신호 교차로 좌회전 vs 직진 (차13-1)' where id = 'ee629ba3-cbc8-407a-bddc-bfb744c94b5c';
update posts set analysis = '{"summary":"왕복2차선 시골도로에서 직진 주행 중, 식당 주차장에서 출발한 상대 차량이 반대 차선으로 진입하는 과정에서 본인 차량 조수석 측면에 충돌한 사고입니다. 상대 차량은 안전지대(황색 노면 표시)를 넘어 진입하였으며, 전방 주시를 소홀히 한 채 차량을 돌렸다고 진술하였습니다. 이는 도로 외 구역(주차장)에서 도로로 진입 시 안전 의무를 위반한 전형적인 사례입니다.","chartCode":"차31-1","chartName":"도로 외 구역(주차장)에서 도로 진입 시 직진 차량과의 충돌","ratio":{"a":{"label":"본인 차량 (직진 주행)","percent":10},"b":{"label":"상대 차량 (주차장 출발 도로 진입)","percent":90},"reason":"상대 차량은 도로 외 구역(식당 주차장)에서 도로로 진입할 때 안전 확인 의무를 현저히 위반하였고, 황색 안전지대를 무단으로 넘어 반대 차선으로 직접 진입하려 한 과실이 매우 큽니다. 본인 차량은 정상적으로 직진 중이었으나, 시골 도로 특성상 식당 등 도로 외 출입구 존재를 인지하고 방어 운전을 할 여지가 있어 소폭의 과실(10%)이 인정될 수 있습니다. 결론적으로 상대 차량의 일방적 과실이 지배적입니다."},"laws":[{"name":"도로교통법 제18조(횡단 등의 금지)","content":"차마의 운전자는 안전지대 등 안전표지에 의하여 진입이 금지된 장소에 진입하여서는 아니 된다.","relevance":"상대 차량이 황색 안전지대를 무단으로 가로질러 반대 차선으로 진입한 행위에 해당합니다.","effect":"안전지대 침범은 명백한 법규 위반으로, 상대방 과실을 대폭 가중시킵니다."},{"name":"도로교통법 제19조(안전거리 확보 등)","content":"모든 차의 운전자는 차의 진로를 변경하거나 도로 이외의 장소에서 진입할 경우 주변 차량의 통행을 방해하지 않도록 충분히 안전을 확인하여야 한다.","relevance":"상대 차량이 주차장에서 도로로 진입하면서 직진 중인 본인 차량을 확인하지 못한 전방 주시 태만에 해당합니다.","effect":"안전 확인 의무 위반으로 상대방의 주된 과실 근거가 됩니다."},{"name":"도로교통법 제25조(교차로 통행방법)","content":"도로 외의 곳에서 도로로 진입하는 차마의 운전자는 그 차마가 통행하고 있는 도로를 통행하는 차마에 양보하여야 한다.","relevance":"주차장(도로 외 구역)에서 도로로 진입하는 상대 차량은 직진 차량인 본인 차량에 절대적으로 양보할 의무가 있습니다.","effect":"양보 의무 위반으로 상대방 과실이 크게 인정됩니다."}],"cases":[{"title":"주차장 출발 차량과 도로 직진 차량 충돌 사건","facts":"피고 차량이 음식점 주차장에서 출발하여 도로로 진입하는 과정에서 안전 확인을 소홀히 하여 정상 직진 중이던 원고 차량의 측면과 충돌하였고, 노면에 표시된 황색 안전지대를 침범한 사실이 인정되었습니다.","ruling":"도로 외 진입 차량(가해) 90% : 직진 차량(피해) 10%","reason":"도로 외 구역에서 진입하는 차량은 도로 통행 차량에 대한 절대적 양보 의무가 있으며, 안전지대 침범 및 전방 주시 태만이 복합적으로 인정되어 가해 차량에 높은 과실이 부과되었습니다."},{"title":"식당 주차장 진출 차량 반대 차선 직접 진입 충돌 사건","facts":"가해 차량이 식당 주차장에서 나와 반대 차선으로 직접 진입(유턴에 준하는 행동)하는 과정에서 황색 안전지대를 무단 통과하여 직진 중이던 피해 차량 조수석 측면과 충돌하였습니다.","ruling":"주차장 진출 차량(가해) 85~90% : 직진 차량(피해) 10~15%","reason":"반대 차선으로의 직접 진입은 매우 위험한 행동으로 가해 차량의 과실이 압도적으로 인정되었으며, 피해 차량은 시골 도로에서의 방어 운전 미흡 정도만 소과실로 인정되었습니다."}],"notes":["황색 안전지대 침범은 법규 위반 사항으로 상대방 과실을 더욱 가중시키는 핵심 요소입니다.","상대 차량 운전자가 ''앞 차량을 먼저 보내고 확인 못했다''고 진술한 것은 전방 주시 태만을 스스로 인정한 것으로, 과실 판단에 불리하게 작용합니다.","블랙박스 영상(본인 차량 및 주변 CCTV)이 있다면 과실 입증에 매우 유리합니다.","조수석 측면 충돌 부위는 본인 차량이 직진 중이었음을 물리적으로 뒷받침하는 증거가 됩니다.","사고 현장 사진(안전지대 노면 표시, 충돌 흔적, 차량 파손 위치)을 반드시 보존하시기 바랍니다."],"needed":["블랙박스 영상 또는 주변 CCTV 영상 확보 여부","사고 당시 본인 차량의 정확한 주행 속도","상대 차량의 진입 각도 및 정확한 충돌 지점 사진","경찰 사고 현장 조사 결과 및 사고 발생 확인서","상대 차량 보험사의 사고 접수 여부 및 과실 인정 여부","황색 안전지대 위치와 상대 차량 진입 경로 관계를 보여주는 현장 사진"]}'::jsonb, fault_ratio_a = 10, fault_ratio_b = 90, chart_code = '차31-1', summary = '왕복2차선 시골도로에서 직진 주행 중, 식당 주차장에서 출발한 상대 차량이 반대 차선으로 진입하는 과정에서 본인 차량 조수석 측면에 충돌한 사고입니다. 상대 차량은 안전지대(황색 노면 표시)를 넘어 진입하였으며, 전방 주시를 소홀히 한 채 차량을 돌렸다고 진술하였습니다. 이는 도로 외 구역(주차장)에서 도로로 진입 시 안전 의무를 위반한 전형적인 사례입니다.', title = '주차장 진출 vs 본선 직진 (차31-1)' where id = '855f60ea-0a0f-4c77-a8b9-52719eb15cc1';

commit;
